var documenterSearchIndex = {"docs":
[{"category":"section","location":"examples/03_acausal_coupling/#Example-3:-Acausal-Coupling-(Tapered-Multi-Compartment-Cable)","page":"03 acausal coupling","text":"Let's look at the acausal side of ModelingToolkit. Unlike directed chemical synapses, gap junctions (electrical couplings) are bidirectional. We'll build a 5-compartment passive dendrite that tapers in size down its length, and inject current at the soma to observe classic cable-theory voltage attenuation.\n\n\n\nusing MTKNeuralToolkit\nusing ModelingToolkit: mtkcompile, @named\nusing ModelingToolkitStandardLibrary.Blocks: Sine\nusing OrdinaryDiffEq\nusing Plots","title":"Example 3: Acausal Coupling (Tapered Multi-Compartment Cable)"},{"category":"section","location":"examples/03_acausal_coupling/#1.-Build-Passive-Compartments-with-Heterogeneous-Geometries","page":"03 acausal coupling","text":"top = Scalar()\n\nDefine a tapering geometry: the soma is large, and distal dendrites are small. We'll keep standard membrane capacitance (10 text mu Fcm^2) and just change the area.\n\nareas = [0.0628, 0.0314, 0.0157, 0.0078, 0.0039] #cm^2\n\nfunction build_passive_compartment(name::Symbol, area::Float64)\n    geom = Geometry(area=area, C_m=1.0) #Geometry struct handles biophysical scaling\n    @named cap  = Capacitor(topology=top, C=1.0, geometry=geom)\n    @named leak = GenericChannel(topology=top, g=0.3, E_rev=-65.0, gates=GateSpec[], geometry=geom)\n\n    return build_compartment(cap, [leak]; name=name, V_init=-65.0, topology=top)\nend\n\nCreate a chain of compartments with decreasing area\n\nN = 5\ncable = [build_passive_compartment(Symbol(:comp, i), areas[i]) for i in 1:N]\n\n","title":"1. Build Passive Compartments with Heterogeneous Geometries"},{"category":"section","location":"examples/03_acausal_coupling/#2.-Connect-Compartments-with-Gap-Junctions","page":"03 acausal coupling","text":"The axial resistance between two compartments is given by:\n\nR = fracR_i cdot LA\n\nFor simplicity, let's say internal resistivity R_i multiplied by length L is 10. Smaller areas mean higher axial resistance, which causes more voltage attenuation. We'll calculate R based on the average area of the two connected compartments.\n\nnote: Naming Systems in Loops\nYou must give unique names to systems created in a loop.\n\ncoupling_specs = CouplingSpec[]\nfor i in 1:(N-1)\n    avg_area = (areas[i] + areas[i+1]) / 2.0\n    R_axial = 1.0 / avg_area\n    gj = GapJunction(R=R_axial; name=Symbol(:gj_, i))\n    push!(coupling_specs, CouplingSpec(cable[i], cable[i+1], gj))\nend\n\n","title":"2. Connect Compartments with Gap Junctions"},{"category":"section","location":"examples/03_acausal_coupling/#3.-Driving-Stimuli","page":"03 acausal coupling","text":"Inject a slow sinusoidal current only into the first compartment (the soma)\n\n@named current_driver = Sine(amplitude=5.0, frequency=0.05, offset=5.0)\n\ndrivers = [(1, current_driver)]\n\n","title":"3. Driving Stimuli"},{"category":"section","location":"examples/03_acausal_coupling/#4.-Build-and-Simulate-the-Network","page":"03 acausal coupling","text":"net = build_acausal_network(cable;\n                            coupling_specs=coupling_specs,\n                            drivers=drivers,\n                            name=:cable_net)\n\nprintln(\"Compiling acausal cable network...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 200.0))\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23())\n\n","title":"4. Build and Simulate the Network"},{"category":"section","location":"examples/03_acausal_coupling/#5.-Plot-the-Results","page":"03 acausal coupling","text":"p = plot(title=\"Example 3: Tapered Multi-Compartment Cable\",\n         xlabel=\"Time (ms)\", ylabel=\"V (mV)\")\n\nfor i in 1:N\n    comp_sys = getproperty(sys, Symbol(:comp, i))\n    plot!(p, sol, idxs=[getproperty(comp_sys, :cap).v], label=\"Comp $i (A=$(areas[i]))\")\nend\np\n\n\n\nThis page was generated using Literate.jl.","title":"5. Plot the Results"},{"category":"section","location":"examples/09_parameter_estimation_conductance/#Example-9:-Parameter-Estimation-of-Ion-Channel-Conductances","page":"09 parameter estimation conductance","text":"using MTKNeuralToolkit\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing Plots","title":"Example 9: Parameter Estimation of Ion Channel Conductances"},{"category":"section","location":"examples/09_parameter_estimation_conductance/#Build-the-True-System-and-Generate-Data","page":"09 parameter estimation conductance","text":"top = Scalar()\n\nfunction build_hh_neuron(name::Symbol; gNa=120.0, gK=36.0)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa)\n    @named k    = PotassiumChannel(topology=top, g=gK)\n    @named leak = LeakChannel(topology=top)\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\ntrue_gNa = 120.0\ntrue_gK  = 36.0\n\ntrue_neuron = build_hh_neuron(:true_neuron; gNa=true_gNa, gK=true_gK)\ndrivers = [(1, 10.0)]\ntrue_net = build_acausal_network([true_neuron]; drivers=drivers, name=:true_net)\n\nprintln(\"Compiling true system...\")\nsys = mtkcompile(true_net.sys)\nodeprob = ODEProblem(sys, [], (0.0, 100.0))\n\ntimesteps = 0.0:0.1:100.0\nprintln(\"Generating training data...\")\nsol = solve(odeprob, Tsit5(); saveat=timesteps)\ndata = Array(sol)","title":"Build the True System & Generate Data"},{"category":"section","location":"examples/09_parameter_estimation_conductance/#Setup-the-Optimization-Problem","page":"09 parameter estimation conductance","text":"guess_gNa = 80.0\nguess_gK  = 20.0\n\nfit_neuron = build_hh_neuron(:fit_neuron; gNa=guess_gNa, gK=guess_gK)\nfit_net = build_acausal_network([fit_neuron]; drivers=drivers, name=:fit_net)\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, 100.0))\n\ngNa_sym = fit_sys.fit_neuron.na.g\ngK_sym  = fit_sys.fit_neuron.k.g\n\nsetter = setp(fit_prob, [gNa_sym, gK_sym])\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nfunction loss(x, p)\n    prob, timesteps, data, setter, diffcache = p\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n    setter(ps, x)\n    newprob = remake(prob; p = ps)\n    sol = solve(newprob, Tsit5(); saveat=timesteps)\n    if size(Array(sol)) != size(data)\n        return Inf\n    end\n    return sum(abs2, Array(sol) .- data) / length(data)\nend\n\nopt_params = (fit_prob, timesteps, data, setter, diffcache)\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\noptprob = OptimizationProblem(optfn, [guess_gNa, guess_gK], opt_params)","title":"Setup the Optimization Problem"},{"category":"section","location":"examples/09_parameter_estimation_conductance/#Optimize-and-Plot","page":"09 parameter estimation conductance","text":"println(\"Solving with initial guesses for visualization...\")\n\nCapture the behavior before optimization to show how far it came\n\ninit_sol = solve(fit_prob, Tsit5(); saveat=timesteps)\n\nprintln(\"Starting optimization...\")\nres = solve(optprob, BFGS(); maxiters=300)\n\nprintln(\"True conductances: gNa = $true_gNa, gK = $true_gK\")\nprintln(\"Recovered conductances: gNa = $(res.u[1]), gK = $(res.u[2])\")\n\nSolve with the optimized parameters\n\nopt_ps = parameter_values(fit_prob)\nopt_buffer = copy(canonicalize(Tunable(), opt_ps)[1])\nopt_ps = replace(Tunable(), opt_ps, opt_buffer)\nsetter(opt_ps, res.u)\nopt_prob_final = remake(fit_prob; p=opt_ps)\n\nopt_sol = solve(opt_prob_final, Tsit5(); saveat=timesteps)\n\np1 = plot(timesteps, data[1, :], label=\"True Voltage\", lw=2, color=:black)\nplot!(p1, timesteps, init_sol[1, :], label=\"Initial Guess\", ls=:dot, lw=2, color=:gray)\nplot!(p1, timesteps, opt_sol[1, :], label=\"Fitted Voltage\", ls=:dash, lw=2, color=:red)\ntitle!(p1, \"Parameter Estimation of HH Conductances\")\nxlabel!(\"Time (ms)\")\nylabel!(\"V (mV)\")\np1\n\n\n\nThis page was generated using Literate.jl.","title":"Optimize and Plot"},{"category":"section","location":"examples/02_directed_synaptic_connection/#Example-2:-Directed-Synaptic-Connection-(Two-Neurons)","page":"02 directed synaptic connection","text":"Now let's connect two neurons. This example introduces network assembly and chemical synapses by linking a presynaptic neuron to a postsynaptic one via an exponential synapse.\n\nInstead of building the HH channels from scratch like we did in Example 1, we'll use the pre-built channels from the MTKNeuralToolkit.HodgkinHuxley standard library to show how quickly you can spin up standard models.\n\n\n\nusing MTKNeuralToolkit\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing ModelingToolkitStandardLibrary.Blocks: Sine\nusing OrdinaryDiffEq\nusing Plots","title":"Example 2: Directed Synaptic Connection (Two Neurons)"},{"category":"section","location":"examples/02_directed_synaptic_connection/#1.-Build-Two-Neurons-using-the-Standard-Library","page":"02 directed synaptic connection","text":"top = Scalar()\n\nThis helper function shows how to pass kwargs to the standard library channels. You can tweak maximal conductances (g) or reversal potentials (E_rev) without rewriting the gating dynamics from scratch.\n\nfunction build_hh_neuron(name::Symbol; gNa=120.0, ENa=50.0, gK=36.0, EK=-77.0,\n                                       gleak=0.3, Eleak=-54.4)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa, E_rev=ENa)\n    @named k    = PotassiumChannel(topology=top, g=gK, E_rev=EK)\n    @named leak = LeakChannel(topology=top, g=gleak, E_rev=Eleak)\n\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\npre_neuron  = build_hh_neuron(:pre_neuron)\n\nWe'll give the postsynaptic neuron altered channel parameters (e.g., a lower sodium conductance and a different leak reversal) to make it distinct.\n\npost_neuron = build_hh_neuron(:post_neuron; gNa=80.0, ENa=45.0, gleak=0.5)\n\n","title":"1. Build Two Neurons using the Standard Library"},{"category":"section","location":"examples/02_directed_synaptic_connection/#2.-Define-the-Synapse","page":"02 directed synaptic connection","text":"ExpSynapse is a continuous, sigmoid-driven exponential synapse. When the presynaptic voltage crosses the threshold (V_th), the gating variable s increases, injecting current into the postsynaptic compartment.\n\n@named excitatory_synapse = ExpSynapse(g_max=2.0, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\ntip: Making an Inhibitory Synapse\nTo make this synapse inhibitory, you just change E_rev to a value below the postsynaptic resting potential (e.g., E_rev=-80.0). No other code changes are needed.\n\n@named inhibitory_synapse = ExpSynapse(g_max=2.0, τ=5.0, E_rev=-80.0, V_th=-20.0, slope=2.0)\n\ntip: Custom Synapses\nLook at the source code for ExpSynapse: it's pretty simple! You can modify the equations to make your own custom synapse. The interface is extremely flexible: you can have complicated multi-state synapses.\n\n","title":"2. Define the Synapse"},{"category":"section","location":"examples/02_directed_synaptic_connection/#3.-Wire-the-Network-using-SynapseSpec","page":"02 directed synaptic connection","text":"A SynapseSpec maps the pre- and post-synaptic voltages to the synapse block, and designates which current variable in the postsynaptic compartment will receive the injected current.\n\nsynapse_specs = [\n    SynapseSpec(\n        pre_neuron.interfaces.V,\n        post_neuron.interfaces.V,\n        post_neuron.interfaces.I_syn,\n        excitatory_synapse\n    )\n]\n\n","title":"3. Wire the Network using SynapseSpec"},{"category":"section","location":"examples/02_directed_synaptic_connection/#4.-Driving-Stimuli","page":"02 directed synaptic connection","text":"We'll drive the presynaptic neuron with a time-varying sinusoidal current so it spikes rhythmically. The postsynaptic neuron receives no external drive, so any spiking it does is purely from the synaptic connection.\n\n@named current_driver = Sine(amplitude=8.0, frequency=0.05, offset=8.0)\n\ndrivers = [(1, current_driver)]\n\n","title":"4. Driving Stimuli"},{"category":"section","location":"examples/02_directed_synaptic_connection/#5.-Build-and-Simulate-the-Network","page":"02 directed synaptic connection","text":"net = build_acausal_network([pre_neuron, post_neuron];\n                            synapse_specs=synapse_specs,\n                            drivers=drivers,\n                            name=:two_neuron_net)\n\nprintln(\"Compiling 2-neuron network...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 200.0))\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23())\n\n","title":"5. Build and Simulate the Network"},{"category":"section","location":"examples/02_directed_synaptic_connection/#6.-Plot-the-Results","page":"02 directed synaptic connection","text":"p1 = plot(sol, idxs=[sys.pre_neuron.cap.v],\n          title=\"Presynaptic Neuron (Driven)\", ylabel=\"V (mV)\", legend=false)\n\np2 = plot(sol, idxs=[sys.post_neuron.cap.v],\n          title=\"Postsynaptic Neuron (Synaptically Driven)\", ylabel=\"V (mV)\", legend=false)\n\np3 = plot(sol, idxs=[sys.excitatory_synapse.I_syn],\n          title=\"Synaptic Current\", ylabel=\"I_syn\", xlabel=\"Time (ms)\", legend=false)\n\nplot(p1, p2, p3, layout=(3,1), size=(800, 700))\n\n\n\nThis page was generated using Literate.jl.","title":"6. Plot the Results"},{"category":"section","location":"examples/01_single_compartment_HH/#Example-1:-Building-a-Single-Compartment-Hodgkin-Huxley-Neuron-from-Scratch","page":"01 single compartment HH","text":"This example introduces the core acausal electrical primitives of MTKNeuralToolkit. We'll use a GateSpec helper to quickly make customisable ion channels and hook them up to run a hodgkin huxley neuron. Note that the next example builds the ion channels from first principles, which is barely any harder.\n\n\n\nusing MTKNeuralToolkit\nusing ModelingToolkit: mtkcompile, @named, t_nounits as t\nusing OrdinaryDiffEq\nusing Plots","title":"Example 1: Building a Single-Compartment Hodgkin-Huxley Neuron from Scratch"},{"category":"section","location":"examples/01_single_compartment_HH/#1.-Define-Ion-Channel-Gating-Dynamics","page":"01 single compartment HH","text":"We use the standard Hodgkin-Huxley formulations (Dayan & Abbott) where V_textrest = -65 text mV. Here, we return the alpha and beta rates as a tuple.\n\nhh_na_m = v -> (\n    0.1 .* (v .+ 40.0) ./ (1.0 .- exp.(-(v .+ 40.0) ./ 10.0)),  #alpha_m\n    4.0 .* exp.(-(v .+ 65.0) ./ 18.0)                           #beta_h\n)\n\nhh_na_h = v -> (\n    0.07 .* exp.(-(v .+ 65.0) ./ 20.0),                         #alpha_h\n    1.0 ./ (1.0 .+ exp.(-(v .+ 35.0) ./ 10.0))                 #beta_h\n)","title":"1. Define Ion Channel Gating Dynamics"},{"category":"section","location":"examples/01_single_compartment_HH/#Defining-Gating-Dynamics:-Alpha/Beta-vs.-Infinity/Tau","page":"01 single compartment HH","text":"There are two common ways to define gating dynamics.","title":"Defining Gating Dynamics: Alpha/Beta vs. Infinity/Tau"},{"category":"section","location":"examples/01_single_compartment_HH/#Method-1:-Alpha/Beta-Formulation","page":"01 single compartment HH","text":"hh_k_n_ab = v -> (\n    0.01 .* (v .+ 55.0) ./ (1.0 .- exp.(-(v .+ 55.0) ./ 10.0)), #alpha_n\n    0.125 .* exp.(-(v .+ 65.0) ./ 80.0)                        #beta_n\n)","title":"Method 1: Alpha/Beta Formulation"},{"category":"section","location":"examples/01_single_compartment_HH/#Method-2:-Infinity/Tau-Formulation-(using-the-InfTau-helper)","page":"01 single compartment HH","text":"Instead of writing out the alpha/beta functions, you might only have the steady-state (inf) and time constant (tau) curves. MTKNeuralToolkit provides the InfTau helper to convert these into the internal alpha/beta formulation:\n\nalpha = fractextinftau quad textand quad beta = frac1 - textinftau\n\nHere, we define n_inf and tau_n mathematically equivalent to Method 1 so you can see how it maps over:\n\nn_alpha(v) = 0.01 .* (v .+ 55.0) ./ (1.0 .- exp.(-(v .+ 55.0) ./ 10.0))\nn_beta(v)  = 0.125 .* exp.(-(v .+ 65.0) ./ 80.0)\nn_inf(v)   = n_alpha(v) ./ (n_alpha(v) .+ n_beta(v))\ntau_n(v)   = 1.0 ./ (n_alpha(v) .+ n_beta(v))\nhh_k_n_inftau = InfTau(n_inf, tau_n)\n\n","title":"Method 2: Infinity/Tau Formulation (using the InfTau helper)"},{"category":"section","location":"examples/01_single_compartment_HH/#2.-Define-Gate-Specifications","page":"01 single compartment HH","text":"At V = -65 text mV, the steady-state values for the gates are:\n\nm = 0052\nh = 0596\nn = 0317\n\nsodium_gates = [\n    GateSpec(:m, 3, 0.052, hh_na_m),\n    GateSpec(:h, 1, 0.596, hh_na_h)\n]\n\nWe're using the InfTau formulation (hh_k_n_inftau) here to show how it works, but swapping it for hh_k_n_ab (the alpha/beta version) gives you the exact same dynamics.\n\nnote: Namespace Clashes\nWe name the K gate n_gate instead of just n to avoid a namespace clash with the negative electrical pin n in MTK's OnePort.\n\npotassium_gates = [\n    GateSpec(:n_gate, 4, 0.317, hh_k_n_inftau)\n]\n\n","title":"2. Define Gate Specifications"},{"category":"section","location":"examples/01_single_compartment_HH/#3.-Build-the-Electrical-Components","page":"01 single compartment HH","text":"First, we instantiate the capacitor and our ion channels. When you pass a GateSpec array to GenericChannel, it creates the ODEs for the gating variables and connects the acausal OnePort for you.\n\ntop = Scalar() #Define a single-neuron topology\n\n@named soma_cap = Capacitor(topology=top, C=1.0)\n@named na_ch = GenericChannel(topology=top, g=120.0, E_rev=50.0,  gates=sodium_gates)\n@named k_ch  = GenericChannel(topology=top, g=36.0,  E_rev=-77.0, gates=potassium_gates)\n@named leak  = GenericChannel(topology=top, g=0.3,   E_rev=-54.4, gates=GateSpec[]) #No gates = pure leak\n\n","title":"3. Build the Electrical Components"},{"category":"section","location":"examples/01_single_compartment_HH/#4.-Assemble-the-Compartment","page":"01 single compartment HH","text":"build_compartment connects all the positive pins  to the membrane voltage, grounds the negative pins, and wires up the injected currents. It returns a Compartment struct containing the MTK System and its exposed interfaces.\n\nchannels = [na_ch, k_ch, leak]\n\nsoma = build_compartment(soma_cap, channels;\n                         name=:soma,\n                         V_init=-65.0,\n                         topology=top)\n\n","title":"4. Assemble the Compartment"},{"category":"section","location":"examples/01_single_compartment_HH/#5.-Build-and-Simulate-the-Network","page":"01 single compartment HH","text":"A single neuron is just a network with one node. We'll drive it with a constant 10.0 mA current injection and solve it. Later examples make the simple extension of driving with time-varying currents.\n\nwarning: Time To First Plot (TTFP)\nThe first time you run this, Julia has to JIT-compile the symbolic system and the differential equation solver. This might take 10-30 seconds. Subsequent runs, or tweaking parameters and re-running, will be much faster.\n\ndrivers = [(1, 10.0)] #(Index 1, Current 10.0)\n\nnet = build_acausal_network([soma]; drivers=drivers, name=:single_neuron)\n\nprintln(\"Compiling single compartment...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 100.0))\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23(), reltol=1e-4, abstol=1e-4)\n\n","title":"5. Build and Simulate the Network"},{"category":"section","location":"examples/01_single_compartment_HH/#6.-Plot-the-Results","page":"01 single compartment HH","text":"Since MTKNeuralToolkit is built on ModelingToolkit, every variable in the system (gating states, alpha/beta rates, local channel currents) is a named symbolic variable. You don't need custom logging callbacks to observe them; you just access them via the compiled system's namespace.","title":"6. Plot the Results"},{"category":"section","location":"examples/01_single_compartment_HH/#6a.-Plot-the-main-membrane-voltage","page":"01 single compartment HH","text":"p1 = plot(sol, idxs=[sys.soma.soma_cap.v],\n          title=\"Example 1: Membrane Potential\",\n          ylabel=\"V (mV)\", legend=false)","title":"6a. Plot the main membrane voltage"},{"category":"section","location":"examples/01_single_compartment_HH/#6b.-Plot-the-internal-HH-gating-variables-(m,-h,-n)","page":"01 single compartment HH","text":"Here we reach into the sodium channel (na_ch) and potassium channel (k_ch) components we created back in Step 3.\n\np2 = plot(sol, idxs=[sys.soma.na_ch.m, sys.soma.na_ch.h, sys.soma.k_ch.n_gate],\n          title=\"Gating Variables\",\n          labels=[\"m (Na+)\" \"h (Na+)\" \"n (K+)\"],\n          ylabel=\"Fraction open\", legend=:right)","title":"6b. Plot the internal HH gating variables (m, h, n)"},{"category":"section","location":"examples/01_single_compartment_HH/#6c.-Plot-the-individual-currents-flowing-through-each-channel","page":"01 single compartment HH","text":"p3 = plot(sol, idxs=[sys.soma.na_ch.i, sys.soma.k_ch.i, sys.soma.leak.i],\n          title=\"Channel Currents\",\n          labels=[\"I_Na\" \"I_K\" \"I_Leak\"],\n          ylabel=\"Current (mA)\", xlabel=\"Time (ms)\", legend=:right)\n\nplot(p1, p2, p3, layout=(3,1), size=(800, 900))\n\n\n\nThis page was generated using Literate.jl.","title":"6c. Plot the individual currents flowing through each channel"},{"category":"section","location":"examples/12_pem_single_neuron/#**12.**-Parameter-Estimation:-Single-Neuron","page":"12 pem single neuron","text":"","title":"12. Parameter Estimation: Single Neuron"},{"category":"section","location":"examples/12_pem_single_neuron/#Introduction","page":"12 pem single neuron","text":"In this example, we demonstrate the filtering power of the Prediction Error Method (PEM). We generate data from a true Hodgkin-Huxley neuron, add Gaussian noise to the voltage trace, and then attempt to recover the conductances. The PEM observer channel acts like a fixed gain Kalman Filter, absorbing the noise while allowing the optimiser to find the true underlying parameters without overfitting the noise.\n\nusing MTKNeuralToolkit\nusing SymbolicIndexingInterface: getu\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing OrdinaryDiffEqRosenbrock\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing DataInterpolations\nusing SciMLBase\nusing Plots\nusing Markdown\nusing Random","title":"Introduction"},{"category":"section","location":"examples/12_pem_single_neuron/#1.-Build-the-True-System-and-Generate-Noisy-Data","page":"12 pem single neuron","text":"top = Scalar()\n\nfunction build_hh_neuron(name::Symbol; gNa=120.0, gK=36.0, gleak=0.3, pem=false, itps=nothing, K=1.0)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa)\n    @named k    = PotassiumChannel(topology=top, g=gK)\n    @named leak = LeakChannel(topology=top, g=gleak)\n    channels = [na, k, leak]\n    if pem\n        @named pem_ch = PEMObservationChannel(itps=itps, K_init=K, topology=top)\n        push!(channels, pem_ch)\n    end\n    return build_compartment(cap, channels; name=name, V_init=-65.0, topology=top)\nend\n\ntrue_gNa = 120.0\ntrue_gK  = 36.0\ntrue_gleak = 0.3\n\ntrue_neuron = build_hh_neuron(:true_neuron; gNa=true_gNa, gK=true_gK, gleak=true_gleak)\n\ndrivers = [(1, 8.0)]\ntrue_net = build_acausal_network([true_neuron]; drivers=drivers, name=:true_net)\nEND_TIME= 100.0\n\n\ntrue_sys = mtkcompile(true_net.sys)\ntrue_prob = ODEProblem(true_sys, [], (0.0, END_TIME))\ntimesteps = 0.0:0.1:END_TIME\n\ntrue_sol = solve(true_prob, Rodas5(); saveat=timesteps)\nV_data_clean = true_sol[true_sys.true_neuron.cap.v];\nnothing #hide\n\nAdd 3 mV Gaussian noise to the data\n\nRandom.seed!(42)\nnoise_level = 3.0\nV_data_noisy = V_data_clean .+ noise_level .* randn(length(V_data_clean))\nitp_V = LinearInterpolation(V_data_noisy, timesteps);\nnothing #hide","title":"1. Build the True System & Generate Noisy Data"},{"category":"section","location":"examples/12_pem_single_neuron/#2.-Setup-the-PEM-Optimization-Problem","page":"12 pem single neuron","text":"We create a model neuron with terrible initial guesses and attach a PEM observer to the noisy data.\n\nguess_gNa = 10.0\nguess_gK  = 100.0\nguess_gleak = 10.3\n\nfit_neuron = build_hh_neuron(:fit_neuron; gNa=guess_gNa, gK=guess_gK, gleak=guess_gleak, pem=true, itps=[itp_V], K=2.0)\nfit_net = build_acausal_network([fit_neuron]; drivers=drivers, name=:fit_net)\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, END_TIME))\n\ngNa_sym = fit_sys.fit_neuron.na.g\ngK_sym  = fit_sys.fit_neuron.k.g\ngleak_sym = fit_sys.fit_neuron.leak.g\n\nsetter = setp(fit_prob, [gNa_sym, gK_sym, gleak_sym])\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nv_getter = getu(fit_prob, fit_sys.fit_neuron.cap.v)\ni_pem_getter = getu(fit_prob, fit_sys.fit_neuron.pem_ch.i);\nnothing #hide","title":"2. Setup the PEM Optimization Problem"},{"category":"section","location":"examples/12_pem_single_neuron/#3.-Define-Loss-Function-and-Optimize","page":"12 pem single neuron","text":"We calculate a multi-objective loss based on both the tracking error (voltage) and the observer effort (current). This forces the system to track the data while penalizing the controller from \"cheating\" to force bad parameters to fit.\n\nfunction loss(x, p)\n    prob, timesteps, V_data_noisy, setter, diffcache, v_getter, i_pem_getter = p\n\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n    setter(ps, x)\n    newprob = remake(prob; p=ps)\n    sol = solve(newprob, Rodas5(); saveat=timesteps, reltol=1e-8, abstol=1e-8)\n\n    if !SciMLBase.successful_retcode(sol.retcode)\n        return Inf\n    end\n\n    V_fit = v_getter(sol)\n    I_pem = i_pem_getter(sol)\n\n    #Multi-objective cost\n    tracking_error = sum(abs2, V_fit .- V_data_noisy) / length(V_data_noisy)\n    observer_effort = sum(abs2, I_pem) / length(I_pem)\n\n    #Weights\n    alpha = 1.0\n    beta = 1.0\n\n    return alpha * tracking_error + beta * observer_effort\nend\n\nTuple must also have exactly 7 items:\n\nopt_params = (fit_prob, timesteps, V_data_noisy, setter, diffcache, v_getter, i_pem_getter)\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\noptprob = OptimizationProblem(optfn, [guess_gNa, guess_gK, guess_gleak], opt_params)","title":"3. Define Loss Function & Optimize"},{"category":"section","location":"examples/12_pem_single_neuron/#4.-Optimize-and-Plot","page":"12 pem single neuron","text":"To avoid recompiling new systems for the free-running simulations, we simply reuse the compiled fit_sys and set the PEM controller gain (K) to 0.0 to disable the observer.\n\nprintln(\"Starting optimization...\")\nres = solve(optprob, BFGS(); maxiters=1000)\n\nK_sym = fit_sys.fit_neuron.pem_ch.K\nK_setter = setp(fit_prob, [K_sym])\n\n–- 1. Simulate with recovered parameters (WITH PEM) to get observer current –-\n\nopt_ps = parameter_values(fit_prob)\nopt_buffer = copy(canonicalize(Tunable(), opt_ps)[1])\nopt_ps = replace(Tunable(), opt_ps, opt_buffer)\nsetter(opt_ps, res.u) # set recovered parameters\nopt_prob_pem = remake(fit_prob; p=opt_ps)\nopt_sol_pem = solve(opt_prob_pem, Rodas5(); saveat=timesteps, reltol=1e-6, abstol=1e-6)\n\n–- 2. Pure simulation for INITIAL GUESS (No PEM) –-\n\ninit_ps = parameter_values(fit_prob)\ninit_buffer = copy(canonicalize(Tunable(), init_ps)[1])\ninit_ps = replace(Tunable(), init_ps, init_buffer)\nsetter(init_ps, [guess_gNa, guess_gK, guess_gleak])\nK_setter(init_ps, [0.0]) # disable PEM controller\ninit_prob_free = remake(fit_prob; p=init_ps)\ninit_eval_sol = solve(init_prob_free, Rodas5(); saveat=timesteps)\n\n–- 3. Pure simulation for RECOVERED PARAMETERS (No PEM) –-\n\nopt_gNa, opt_gK, opt_gleak = res.u\nfit_ps = parameter_values(fit_prob)\nfit_buffer = copy(canonicalize(Tunable(), fit_ps)[1])\nfit_ps = replace(Tunable(), fit_ps, fit_buffer)\nsetter(fit_ps, [opt_gNa, opt_gK, opt_gleak])\n\ndisable PEM controller\n\nK_setter(fit_ps, [0.0])\nfit_prob_free = remake(fit_prob; p=fit_ps)\nfit_eval_sol = solve(fit_prob_free, Rodas5(); saveat=timesteps)\n\np1 = plot(timesteps, V_data_noisy, label=\"Noisy Target\", color=:gray, lw=1, alpha=0.8)\nplot!(p1, timesteps, V_data_clean, label=\"True Clean\", color=:black, lw=2)\nplot!(p1, timesteps, init_eval_sol[fit_sys.fit_neuron.cap.v], label=\"Initial Guess (Free-Running)\", ls=:dot, lw=2, color=:blue)\nplot!(p1, timesteps, fit_eval_sol[fit_sys.fit_neuron.cap.v], label=\"Fit (Free-Running)\", ls=:dash, lw=2, color=:red)\ntitle!(\"Voltage Trace Recovery (Noisy Data)\")\n\nPlot the observer current.\n\nI_obs = i_pem_getter(opt_sol_pem)\np2 = plot(timesteps, I_obs, label=\"Observer Current\", color=:red, lw=1.5)\ntitle!(\"PEM Observer Current (Absorbing Noise)\")\nhline!([0.0], color=:gray, ls=:dot, label=\"0\")\n\np = plot(p1, p2, layout=(2,1), size=(800, 700), legend=:outertop)\nxlabel!(p, \"Time (ms)\")\nylabel!(p, \"V (mV) / I (nA)\")\np\n\nNote the slight phase lag at the end of the sim.","title":"4. Optimize and Plot"},{"category":"section","location":"examples/12_pem_single_neuron/#5.-Parameter-Comparison","page":"12 pem single neuron","text":"Markdown.parse(\"\"\"\n| Parameter | True Value | Initial Guess | Recovered Value |\n|-----------|------------|---------------|-----------------|\n| gNa       | $true_gNa  | $guess_gNa    | $(round(opt_gNa, digits=3)) |\n| gK        | $true_gK   | $guess_gK     | $(round(opt_gK, digits=3)) |\n| gleak     | $true_gleak| $guess_gleak  | $(round(opt_gleak, digits=3)) |\n\"\"\")\n\n\n\nThis page was generated using Literate.jl.","title":"5. Parameter Comparison"},{"category":"section","location":"examples/06_stdp/#Example-6:-Spike-Timing-Dependent-Plasticity-(STDP)","page":"06 stdp","text":"This example introduces learning and plasticity. We connect two neurons using the STDPSynapse, a continuous, smooth approximation of STDP.\n\nWe drive the presynaptic neuron with a constant current, and the postsynaptic neuron with a slightly different constant current so they spike at different frequencies. The STDP rule will continuously strengthen or weaken the synaptic weight based on their relative spike times. We will plot the dynamic weight variable w to watch learning happen in real-time!\n\nusing MTKNeuralToolkit\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing Plots\n\n##. Build Two Neurons\n\ntop = Scalar()\n\nfunction build_neuron(name::Symbol)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top)\n    @named k    = PotassiumChannel(topology=top)\n    @named leak = LeakChannel(topology=top)\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\npre_neuron  = build_neuron(:pre_neuron)\npost_neuron = build_neuron(:post_neuron)","title":"Example 6: Spike-Timing-Dependent Plasticity (STDP)"},{"category":"section","location":"examples/06_stdp/#Define-the-STDP-Synapse","page":"06 stdp","text":"The STDPSynapse continuously updates its weight w based on the traces x (pre) and y (post).\n\nIf pre spikes before post, x is high when y spikes -> LTP (weight increases)\nIf post spikes before pre, y is high when x spikes -> LTD (weight decreases)\n\n@named stdp_syn = STDPSynapse(g_max=2.0, E_rev=0.0, V_th=0.0, slope=2.0,\n                              τ_s=5.0, τ_plus=20.0, τ_minus=20.0,\n                              A_plus=0.1, A_minus=0.1, w_init=0.5, w_max=1.0, w_min=0.0)\n\nsynapse_specs = [\n    SynapseSpec(\n        pre_neuron.interfaces.V,\n        post_neuron.interfaces.V,\n        post_neuron.interfaces.I_syn,\n        stdp_syn\n    )\n]","title":"Define the STDP Synapse"},{"category":"section","location":"examples/06_stdp/#Driving-Stimuli-(Phase-Shifted-Sine-Waves)","page":"06 stdp","text":"To demonstrate BOTH potentiation and depression, we drive both neurons with the same frequency, but shift the phase. Swap the driver with a higher phase to see either LTP or LTD\n\nusing ModelingToolkitStandardLibrary.Blocks: Sine\n\nPre fires ~10ms before Post (Phase offset of 1 radian)\n\n@named pre_driver  = Sine(amplitude=8.0, frequency=0.2, offset=8.0, phase=1.0)\n@named post_driver = Sine(amplitude=8.0, frequency=0.2, offset=8.0, phase=0.0)\n\ndrivers = [\n    (1, pre_driver),  # Pre fires second\n    (2, post_driver)  # Post fires first -> causes LTD\n]","title":"Driving Stimuli (Phase-Shifted Sine Waves)"},{"category":"section","location":"examples/06_stdp/#Build-and-Simulate","page":"06 stdp","text":"net = build_acausal_network([pre_neuron, post_neuron];\n                            synapse_specs=synapse_specs,\n                            drivers=drivers,\n                            name=:stdp_net)\n\nprintln(\"Compiling STDP network...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 500.0), jac=true, sparse=true)\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23(), reltol=1e-4, abstol=1e-4)","title":"Build and Simulate"},{"category":"section","location":"examples/06_stdp/#Plot-the-Results","page":"06 stdp","text":"p1 = plot(sol, idxs=[sys.pre_neuron.cap.v, sys.post_neuron.cap.v],\n          title=\"Neuron Voltages\", ylabel=\"V (mV)\",\n          labels=[\"Pre\" \"Post\"], legend=:right)\n\nPlot the plastic weight variable! We reach into the synapse namespace to get w.\n\np2 = plot(sol, idxs=[sys.stdp_syn.w],\n          title=\"STDP Synaptic Weight (w)\",\n          ylabel=\"Weight\", xlabel=\"Time (ms)\", legend=false)\n\nPlot the pre and post synaptic traces (x and y) which drive the weight update\n\np3 = plot(sol, idxs=[sys.stdp_syn.x, sys.stdp_syn.y],\n          title=\"STDP Activity Traces\",\n          labels=[\"x (Pre)\" \"y (Post)\"], legend=:right)\n\nplot(p1, p2, p3, layout=(3,1), size=(800, 800))\n\n\n\nThis page was generated using Literate.jl.","title":"Plot the Results"},{"category":"section","location":"examples/13_pem_hidden_chain/#**13.**-Parameter-Estimation:-Hidden-Neuron-Chain","page":"13 pem hidden chain","text":"","title":"13. Parameter Estimation: Hidden Neuron Chain"},{"category":"section","location":"examples/13_pem_hidden_chain/#Introduction","page":"13 pem hidden chain","text":"In this example, we infer the parameters of a completely hidden neuron in a chain. We have a 3-neuron chain (A -> B -> C). Neuron A is driven by an 8.0 nA current. We observe the voltages of A and C, but B is hidden. We must recover the conductances (gNa, gK, gleak) of B and the synaptic weights between A->B and B->C.\n\nTo make the optimization problem difficult, we provide initial guesses that prevent the hidden neuron B from spiking. We intentionally do not constrain the parameters to demonstrate a critical concept in system identification: unidentifiability. Without physiological constraints, the optimizer can find \"non-physical\" parameter combinations (e.g., negative conductances) that still successfully drive the observed output (neuron C).\n\nusing MTKNeuralToolkit\nusing SymbolicIndexingInterface: getu\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing DataInterpolations\nusing SciMLBase\nusing Plots\nusing Markdown","title":"Introduction"},{"category":"section","location":"examples/13_pem_hidden_chain/#1.-Build-the-True-System-and-Generate-Data","page":"13 pem hidden chain","text":"top = Scalar()\n\nfunction build_hh_neuron(name::Symbol; gNa=120.0, gK=36.0, gleak=0.3, pem=false, itps=nothing, K=1.0)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa)\n    @named k    = PotassiumChannel(topology=top, g=gK)\n    @named leak = LeakChannel(topology=top, g=gleak)\n    channels = [na, k, leak]\n    if pem\n        @named pem_ch = PEMObservationChannel(itps=itps, K_init=K, topology=top)\n        push!(channels, pem_ch)\n    end\n    return build_compartment(cap, channels; name=name, V_init=-65.0, topology=top)\nend\n\ntrue_gNa = 120.0\ntrue_gK  = 36.0\ntrue_gleak = 0.3\ntrue_g_syn = 3.0\n\nA_true = build_hh_neuron(:A_true; gNa=true_gNa, gK=true_gK, gleak=true_gleak)\nB_true = build_hh_neuron(:B_true; gNa=true_gNa, gK=true_gK, gleak=true_gleak)\nC_true = build_hh_neuron(:C_true; gNa=true_gNa, gK=true_gK, gleak=true_gleak)\n\n@named syn_AB = ExpSynapse(g_max=true_g_syn, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n@named syn_BC = ExpSynapse(g_max=true_g_syn, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nsynapse_specs = [\n    SynapseSpec(A_true.interfaces.V, B_true.interfaces.V, B_true.interfaces.I_syn, syn_AB),\n    SynapseSpec(B_true.interfaces.V, C_true.interfaces.V, C_true.interfaces.I_syn, syn_BC)\n]\n\ndrivers = [(1, 8.0)]\ntrue_net = build_acausal_network([A_true, B_true, C_true]; synapse_specs=synapse_specs, drivers=drivers, name=:true_net)\n\ntrue_sys = mtkcompile(true_net.sys)\ntrue_prob = ODEProblem(true_sys, [], (0.0, 50.0), jac=true, sparse=true)\ntimesteps = 0.0:0.1:50.0\n\ntrue_sol = solve(true_prob, Rosenbrock23(); saveat=timesteps)\n\nV_data_A = true_sol[true_sys.A_true.cap.v]\nV_data_C = true_sol[true_sys.C_true.cap.v]\n\nitp_A = LinearInterpolation(V_data_A, timesteps)\nitp_C = LinearInterpolation(V_data_C, timesteps);\nnothing #hide","title":"1. Build the True System & Generate Data"},{"category":"section","location":"examples/13_pem_hidden_chain/#2.-Setup-the-PEM-Optimization-Problem","page":"13 pem hidden chain","text":"A and C get PEM observers. B is completely hidden. We intentionally guess terrible parameters for B (including high gleak) and the synapses so the initial model fails to propagate the signal.\n\nguess_gNa = 10.0\nguess_gK  = 100.0\nguess_gleak = 10.0\nguess_g_syn = 0.1\nK_obs = 0.5\n\nA_fit = build_hh_neuron(:A_fit; gNa=true_gNa, gK=true_gK, gleak=true_gleak, pem=true, itps=[itp_A], K=K_obs)\nB_fit = build_hh_neuron(:B_fit; gNa=guess_gNa, gK=guess_gK, gleak=guess_gleak, pem=false)\nC_fit = build_hh_neuron(:C_fit; gNa=true_gNa, gK=true_gK, gleak=true_gleak, pem=true, itps=[itp_C], K=K_obs)\n\n@named syn_AB_fit = ExpSynapse(g_max=guess_g_syn, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n@named syn_BC_fit = ExpSynapse(g_max=guess_g_syn, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nsynapse_specs_fit = [\n    SynapseSpec(A_fit.interfaces.V, B_fit.interfaces.V, B_fit.interfaces.I_syn, syn_AB_fit),\n    SynapseSpec(B_fit.interfaces.V, C_fit.interfaces.V, C_fit.interfaces.I_syn, syn_BC_fit)\n]\n\nfit_net = build_acausal_network([A_fit, B_fit, C_fit]; synapse_specs=synapse_specs_fit, drivers=drivers, name=:fit_net)\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, 50.0), jac=true, sparse=true)\n\nparams_to_fit = [\n    fit_sys.B_fit.na.g, fit_sys.B_fit.k.g, fit_sys.B_fit.leak.g,\n    fit_sys.syn_AB_fit.g_max, fit_sys.syn_BC_fit.g_max\n]\n\nsetter = setp(fit_prob, params_to_fit)\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nv_getter_A = getu(fit_prob, fit_sys.A_fit.cap.v)\nv_getter_C = getu(fit_prob, fit_sys.C_fit.cap.v)","title":"2. Setup the PEM Optimization Problem"},{"category":"section","location":"examples/13_pem_hidden_chain/#3.-Define-Loss-Function-and-Optimize","page":"13 pem hidden chain","text":"function loss(x, p)\n    prob, timesteps, V_data_A, V_data_C, setter, diffcache, v_getter_A, v_getter_C = p\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n    setter(ps, x)\n    newprob = remake(prob; p=ps)\n    sol = solve(newprob, Rosenbrock23(); saveat=timesteps)\n    if !SciMLBase.successful_retcode(sol.retcode)\n        return Inf\n    end\n    V_fit_A = v_getter_A(sol)\n    V_fit_C = v_getter_C(sol)\n    v_error = sum(abs2, V_fit_A .- V_data_A) + sum(abs2, V_fit_C .- V_data_C)\n    return v_error / (length(V_data_A) + length(V_data_C))\nend\n\nopt_params = (fit_prob, timesteps, V_data_A, V_data_C, setter, diffcache, v_getter_A, v_getter_C)\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\n\noptprob = OptimizationProblem(optfn, [guess_gNa, guess_gK, guess_gleak, guess_g_syn, guess_g_syn], opt_params)","title":"3. Define Loss Function & Optimize"},{"category":"section","location":"examples/13_pem_hidden_chain/#4.-Optimize-and-Plot","page":"13 pem hidden chain","text":"println(\"Starting optimization...\")\nres = solve(optprob, BFGS(); maxiters=1000)\nopt_gNa, opt_gK, opt_gleak, opt_g_syn_AB, opt_g_syn_BC = res.u\n\nGrab the PEM K parameters so we can disable them\n\nK_syms = [fit_sys.A_fit.pem_ch.K, fit_sys.C_fit.pem_ch.K]\nK_setter = setp(fit_prob, K_syms)\n\n–- Pure simulation for INITIAL GUESS (No PEM) –-\n\ninit_ps = parameter_values(fit_prob)\ninit_buffer = copy(canonicalize(Tunable(), init_ps)[1])\ninit_ps = replace(Tunable(), init_ps, init_buffer)\nsetter(init_ps, [guess_gNa, guess_gK, guess_gleak, guess_g_syn, guess_g_syn])\nK_setter(init_ps, [0.0, 0.0]) # Disable PEM controllers\ninit_prob_free = remake(fit_prob; p=init_ps)\ninit_sol = solve(init_prob_free, Rosenbrock23(); saveat=timesteps);\nnothing #hide\n\n–- Pure simulation for RECOVERED PARAMETERS (No PEM) –-\n\nfit_ps = parameter_values(fit_prob)\nfit_buffer = copy(canonicalize(Tunable(), fit_ps)[1])\nfit_ps = replace(Tunable(), fit_ps, fit_buffer)\nsetter(fit_ps, res.u)\nK_setter(fit_ps, [0.0, 0.0]) # Disable PEM controllers\nfit_prob_free = remake(fit_prob; p=fit_ps)\nfit_eval_sol = solve(fit_prob_free, Rosenbrock23(); saveat=timesteps);\nnothing #hide\n\n–- Plotting the Free-Running Dynamics –-\n\np1 = plot(timesteps, V_data_A, label=\"True A\", lw=2, color=:black)\nplot!(p1, timesteps, init_sol[fit_sys.A_fit.cap.v], label=\"Init A\", ls=:dot, lw=2, color=:gray)\nplot!(p1, timesteps, fit_eval_sol[fit_sys.A_fit.cap.v], label=\"Fit A\", ls=:dash, lw=2, color=:red)\ntitle!(\"Observed: A\")\n\np2 = plot(timesteps, true_sol[true_sys.B_true.cap.v], label=\"True B\", lw=2, color=:black)\nplot!(p2, timesteps, init_sol[fit_sys.B_fit.cap.v], label=\"Init B\", ls=:dot, lw=2, color=:gray)\nplot!(p2, timesteps, fit_eval_sol[fit_sys.B_fit.cap.v], label=\"Fit B (hidden)\", ls=:dash, lw=2, color=:blue)\ntitle!(\"Hidden: B\")\n\np3 = plot(timesteps, V_data_C, label=\"True C\", lw=2, color=:black)\nplot!(p3, timesteps, init_sol[fit_sys.C_fit.cap.v], label=\"Init C\", ls=:dot, lw=2, color=:gray)\nplot!(p3, timesteps, fit_eval_sol[fit_sys.C_fit.cap.v], label=\"Fit C\", ls=:dash, lw=2, color=:red)\ntitle!(\"Observed: C\")\n\np = plot(p1, p2, p3, layout=(3,1), size=(800, 800), legend=:outertop)\nxlabel!(p, \"Time (ms)\")\nylabel!(p, \"V (mV)\")\np","title":"4. Optimize and Plot"},{"category":"section","location":"examples/13_pem_hidden_chain/#5.-Parameter-Comparison-and-Unidentifiability","page":"13 pem hidden chain","text":"The free-running voltage of neuron C matches the true data quite well. However, if we look at the parameters of the hidden neuron B, we see that the optimizer found a non-physical solution. gNa became negative, and gK was severely reduced.\n\nThis is a classic example of unidentifiability. Because B is hidden, the optimizer only tries to match the input current going into C. By altering B's intrinsic dynamics to a non-physical state and scaling up the synaptic weights, the optimizer found an alternative \"local minimum\" that minimizes the voltage error at C.\n\nMoral of the story: inferring the parameters, or even the behaviour, of a neuron whose voltage you can't see is a thankless task! Exercise for reader: play around with box constraints (easy to implement as charted here) to see if restricting to plausible values helps!\n\nMarkdown.parse(\"\"\"\n| Parameter | True Value | Initial Guess | Recovered Value |\n|-----------|------------|---------------|-----------------|\n| B: gNa    | $true_gNa  | $guess_gNa    | $(round(opt_gNa, digits=3)) |\n| B: gK     | $true_gK   | $guess_gK     | $(round(opt_gK, digits=3)) |\n| B: gleak  | $true_gleak| $guess_gleak  | $(round(opt_gleak, digits=3)) |\n| Syn A->B  | $true_g_syn| $guess_g_syn  | $(round(opt_g_syn_AB, digits=3)) |\n| Syn B->C  | $true_g_syn| $guess_g_syn  | $(round(opt_g_syn_BC, digits=3)) |\n\n**Final Loss:** $(round(res.objective, digits=3))\n\nNotice that despite the non-physical hidden parameters, the final loss is relatively low, indicating a good fit for the *observed* variables (A and C) at the cost of the hidden state (B).\n\"\"\")\n\n\n\nThis page was generated using Literate.jl.","title":"5. Parameter Comparison & Unidentifiability"},{"category":"section","location":"examples/14_pem_vectorized_pop/#**14.**-Parameter-Estimation:-Heterogeneous-Vectorized-Population","page":"14 pem vectorized pop","text":"","title":"14. Parameter Estimation: Heterogeneous Vectorized Population"},{"category":"section","location":"examples/14_pem_vectorized_pop/#Introduction","page":"14 pem vectorized pop","text":"Here we fit the conductances of a larger, heterogeneous E/I microcircuit. We have 10 Excitatory and 3 Inhibitory neurons. To make the dynamics asynchronous, we use random synaptic weight matrices. We attempt a large-scale optimization: fitting the heterogeneous gNa arrays (13 parameters) alongside the shared gK and gleak scalars (4 parameters) for a total of 17 parameters.\n\nusing MTKNeuralToolkit\nusing ModelingToolkit: t_nounits as t, D_nounits as D, connect, Pre\nusing SymbolicIndexingInterface: getu\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing MTKNeuralToolkit: PEMObservationChannel\nusing ModelingToolkit: mtkcompile, @named, @component\nusing OrdinaryDiffEq\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing DataInterpolations\nusing SciMLBase\nusing Plots\nusing Markdown\nusing Random","title":"Introduction"},{"category":"section","location":"examples/14_pem_vectorized_pop/#1.-Build-the-True-System-and-Generate-Data","page":"14 pem vectorized pop","text":"N_E = 10\nN_I = 3\ntop_E = Vectorized(N_E)\ntop_I = Vectorized(N_I);\nnothing #hide\n\nHeterogeneous true sodium conductances\n\ngNa_E_true = collect(range(110.0, 130.0, length=N_E))\ngNa_I_true = collect(range(115.0, 125.0, length=N_I))\n\ntrue_gK = 36.0\ntrue_gleak = 0.3\n\nfunction build_population(name::Symbol, top; gNa, gK, gleak, pem=false, itps=nothing, K=1.0)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa)\n    @named k    = PotassiumChannel(topology=top, g=gK)\n    @named leak = LeakChannel(topology=top, g=gleak)\n    channels = [na, k, leak]\n    if pem\n        @named pem_ch = PEMObservationChannel(itps=itps, K_init=K, topology=top)\n        push!(channels, pem_ch)\n    end\n    return build_compartment(cap, channels; name=name, V_init=-65.0, topology=top)\nend\n\npop_E_true = build_population(:pop_E_true, top_E; gNa=gNa_E_true, gK=true_gK, gleak=true_gleak)\npop_I_true = build_population(:pop_I_true, top_I; gNa=gNa_I_true, gK=true_gK, gleak=true_gleak)\n\nRandom.seed!(42)\nW_EE = 0.5 .* rand(N_E, N_E)\nW_EI = 1.0 .* rand(N_I, N_E)\nW_IE = 2.0 .* rand(N_E, N_I)\nW_II = 1.0 .* rand(N_I, N_I)\n\nsyn_EE = build_synapse_block(pop_E_true, pop_E_true, W_EE; name=:syn_EE, E_rev=0.0)\nsyn_EI = build_synapse_block(pop_E_true, pop_I_true, W_EI; name=:syn_EI, E_rev=0.0)\nsyn_IE = build_synapse_block(pop_I_true, pop_E_true, W_IE; name=:syn_IE, E_rev=-80.0)\nsyn_II = build_synapse_block(pop_I_true, pop_I_true, W_II; name=:syn_II, E_rev=-80.0)\n\nsynapse_specs = [syn_EE, syn_EI, syn_IE, syn_II]\ndrivers = [(1, 15.0)] # Strong kick to E population\n\ntrue_net = build_acausal_network([pop_E_true, pop_I_true]; synapse_specs=synapse_specs, drivers=drivers, name=:true_net)\ntrue_sys = mtkcompile(true_net.sys)\ntrue_prob = ODEProblem(true_sys, [], (0.0, 50.0), jac=true, sparse=true)\ntimesteps = 0.0:0.1:50.0\n\ntrue_sol = solve(true_prob, Rosenbrock23(); saveat=timesteps)\n\nV_data_E_mat = reduce(hcat, true_sol[true_sys.pop_E_true.cap.v])\nV_data_I_mat = reduce(hcat, true_sol[true_sys.pop_I_true.cap.v])\n\nitps_E = [LinearInterpolation(V_data_E_mat[i, :], timesteps) for i in 1:N_E]\nitps_I = [LinearInterpolation(V_data_I_mat[i, :], timesteps) for i in 1:N_I];\nnothing #hide","title":"1. Build the True System & Generate Data"},{"category":"section","location":"examples/14_pem_vectorized_pop/#2.-Setup-the-PEM-Optimization-Problem","page":"14 pem vectorized pop","text":"We fit 17 parameters total: heterogeneous gNa arrays (length 10 and 3) and shared gK/gleak scalars. We intentionally guess terrible values (gNa=10.0, gK=100.0, gleak=10.0) that abolish spiking entirely.\n\nguess_gNa_E = fill(10.0, N_E)\nguess_gNa_I = fill(10.0, N_I)\nguess_gK = 100.0\nguess_gleak = 10.0\n\npop_E_fit = build_population(:pop_E_fit, top_E; gNa=guess_gNa_E, gK=guess_gK, gleak=guess_gleak, pem=true, itps=itps_E, K=2.0)\npop_I_fit = build_population(:pop_I_fit, top_I; gNa=guess_gNa_I, gK=guess_gK, gleak=guess_gleak, pem=true, itps=itps_I, K=2.0)\n\nsyn_EE_fit = build_synapse_block(pop_E_fit, pop_E_fit, W_EE; name=:syn_EE_fit, E_rev=0.0)\nsyn_EI_fit = build_synapse_block(pop_E_fit, pop_I_fit, W_EI; name=:syn_EI_fit, E_rev=0.0)\nsyn_IE_fit = build_synapse_block(pop_I_fit, pop_E_fit, W_IE; name=:syn_IE_fit, E_rev=-80.0)\nsyn_II_fit = build_synapse_block(pop_I_fit, pop_I_fit, W_II; name=:syn_II_fit, E_rev=-80.0)\n\nsynapse_specs_fit = [syn_EE_fit, syn_EI_fit, syn_IE_fit, syn_II_fit]\n\nfit_net = build_acausal_network([pop_E_fit, pop_I_fit]; synapse_specs=synapse_specs_fit, drivers=drivers, name=:fit_net)\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, 50.0), jac=true, sparse=true);\nnothing #hide\n\nExtract symbols for the 17 parameters\n\ngNa_E_sym = fit_sys.pop_E_fit.na.g\ngK_E_sym  = fit_sys.pop_E_fit.k.g\ngleak_E_sym = fit_sys.pop_E_fit.leak.g\ngNa_I_sym = fit_sys.pop_I_fit.na.g\ngK_I_sym  = fit_sys.pop_I_fit.k.g\ngleak_I_sym = fit_sys.pop_I_fit.leak.g\n\nsetter = setp(fit_prob, [gNa_E_sym, gK_E_sym, gleak_E_sym, gNa_I_sym, gK_I_sym, gleak_I_sym])\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nv_getter_E = getu(fit_prob, fit_sys.pop_E_fit.cap.v)\nv_getter_I = getu(fit_prob, fit_sys.pop_I_fit.cap.v)","title":"2. Setup the PEM Optimization Problem"},{"category":"section","location":"examples/14_pem_vectorized_pop/#3.-Define-Loss-Function-and-Optimize","page":"14 pem vectorized pop","text":"function loss(x, p)\n    prob, timesteps, V_data_E, V_data_I, setter, diffcache, v_getter_E, v_getter_I = p\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n\n    #Split the flat x vector into the 6 grouped chunks expected by the setter\n    vals = [\n        x[1:N_E],                      #gNa_E (array of 10)\n        x[N_E + 1],                    #gK_E (scalar)\n        x[N_E + 2],                    #gleak_E (scalar)\n        x[N_E + 3 : N_E + N_I + 2],    #gNa_I (array of 3)\n        x[N_E + N_I + 3],              #gK_I (scalar)\n        x[N_E + N_I + 4]               #gleak_I (scalar)\n    ]\n\n    setter(ps, vals)\n    newprob = remake(prob; p=ps)\n    sol = solve(newprob, Rosenbrock23(); saveat=timesteps)\n    if !SciMLBase.successful_retcode(sol.retcode)\n        return Inf\n    end\n    V_fit_E = reduce(hcat, v_getter_E(sol))\n    V_fit_I = reduce(hcat, v_getter_I(sol))\n    return (sum(abs2, V_fit_E .- V_data_E) + sum(abs2, V_fit_I .- V_data_I)) / (size(V_data_E, 2) * (N_E + N_I))\nend\n\nFlatten the 17 initial guesses into a single vector for the optimizer\n\nx0 = vcat(guess_gNa_E, [guess_gK, guess_gleak], guess_gNa_I, [guess_gK, guess_gleak])\n\nopt_params = (fit_prob, timesteps, V_data_E_mat, V_data_I_mat, setter, diffcache, v_getter_E, v_getter_I)\n\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\noptprob = OptimizationProblem(optfn, x0, opt_params)","title":"3. Define Loss Function & Optimize"},{"category":"section","location":"examples/14_pem_vectorized_pop/#4.-Optimize-and-Plot","page":"14 pem vectorized pop","text":"println(\"Starting optimization (17 parameters)...\")\nres = solve(optprob, BFGS(); maxiters=100)\n\nExtract recovered parameters\n\nopt_gNa_E = res.u[1:N_E]\nopt_gK_E  = res.u[N_E + 1]\nopt_gleak_E = res.u[N_E + 2]\nopt_gNa_I = res.u[N_E + 3 : N_E + N_I + 2]\nopt_gK_I  = res.u[N_E + N_I + 3]\nopt_gleak_I = res.u[N_E + N_I + 4]\n\n–- Pure simulation for INITIAL GUESS (No PEM) –-\n\npop_E_init = build_population(:pop_E_init, top_E; gNa=guess_gNa_E, gK=guess_gK, gleak=guess_gleak)\npop_I_init = build_population(:pop_I_init, top_I; gNa=guess_gNa_I, gK=guess_gK, gleak=guess_gleak)\n\nsyn_EE_init = build_synapse_block(pop_E_init, pop_E_init, W_EE; name=:syn_EE_init, E_rev=0.0)\nsyn_EI_init = build_synapse_block(pop_E_init, pop_I_init, W_EI; name=:syn_EI_init, E_rev=0.0)\nsyn_IE_init = build_synapse_block(pop_I_init, pop_E_init, W_IE; name=:syn_IE_init, E_rev=-80.0)\nsyn_II_init = build_synapse_block(pop_I_init, pop_I_init, W_II; name=:syn_II_init, E_rev=-80.0)\nsynapse_specs_init = [syn_EE_init, syn_EI_init, syn_IE_init, syn_II_init]\n\ninit_net = build_acausal_network([pop_E_init, pop_I_init]; synapse_specs=synapse_specs_init, drivers=drivers, name=:init_net)\ninit_sys = mtkcompile(init_net.sys)\ninit_prob = ODEProblem(init_sys, [], (0.0, 50.0), jac=true, sparse=true)\ninit_sol = solve(init_prob, Rosenbrock23(); saveat=timesteps)\n\n–- Pure simulation for RECOVERED PARAMETERS (No PEM) –-\n\npop_E_eval = build_population(:pop_E_eval, top_E; gNa=opt_gNa_E, gK=opt_gK_E, gleak=opt_gleak_E)\npop_I_eval = build_population(:pop_I_eval, top_I; gNa=opt_gNa_I, gK=opt_gK_I, gleak=opt_gleak_I)\n\nsyn_EE_eval = build_synapse_block(pop_E_eval, pop_E_eval, W_EE; name=:syn_EE_eval, E_rev=0.0)\nsyn_EI_eval = build_synapse_block(pop_E_eval, pop_I_eval, W_EI; name=:syn_EI_eval, E_rev=0.0)\nsyn_IE_eval = build_synapse_block(pop_I_eval, pop_E_eval, W_IE; name=:syn_IE_eval, E_rev=-80.0)\nsyn_II_eval = build_synapse_block(pop_I_eval, pop_I_eval, W_II; name=:syn_II_eval, E_rev=-80.0)\nsynapse_specs_eval = [syn_EE_eval, syn_EI_eval, syn_IE_eval, syn_II_eval]\n\neval_net = build_acausal_network([pop_E_eval, pop_I_eval]; synapse_specs=synapse_specs_eval, drivers=drivers, name=:eval_net)\neval_sys = mtkcompile(eval_net.sys)\neval_prob = ODEProblem(eval_sys, [], (0.0, 50.0), jac=true, sparse=true)\neval_sol = solve(eval_prob, Rosenbrock23(); saveat=timesteps);\nnothing #hide\n\n–- Extract the free-running matrices for plotting –-\n\nV_init_E_mat = reduce(hcat, init_sol[init_sys.pop_E_init.cap.v])\nV_init_I_mat = reduce(hcat, init_sol[init_sys.pop_I_init.cap.v])\nV_eval_E_mat = reduce(hcat, eval_sol[eval_sys.pop_E_eval.cap.v])\nV_eval_I_mat = reduce(hcat, eval_sol[eval_sys.pop_I_eval.cap.v])\n\n–- Plotting the Free-Running Dynamics –-\n\nsubset_E = [1, 5, 10]\nlabels_E_true = [\"True E\" \"\" \"\"]\nlabels_E_init = [\"Init E\" \"\" \"\"]\nlabels_E_fit  = [\"Fit E\" \"\" \"\"]\n\np1 = plot(timesteps, V_data_E_mat[subset_E,:]', color=:black, lw=2, label=labels_E_true)\nplot!(p1, timesteps, V_init_E_mat[subset_E,:]', color=:steelblue, lw=1.5, label=labels_E_init)\nplot!(p1, timesteps, V_eval_E_mat[subset_E,:]', color=:crimson, lw=1.5, label=labels_E_fit)\ntitle!(\"Excitatory Population (Arbitrary Subset)\")\n\nlabels_I_true = [\"True I\" \"\" \"\"]\nlabels_I_init = [\"Init I\" \"\" \"\"]\nlabels_I_fit  = [\"Fit I\" \"\" \"\"]\n\np2 = plot(timesteps, V_data_I_mat', color=:black, lw=2, label=labels_I_true)\nplot!(p2, timesteps, V_init_I_mat', color=:steelblue, lw=1.5, label=labels_I_init)\nplot!(p2, timesteps, V_eval_I_mat', color=:crimson, lw=1.5, label=labels_I_fit)\ntitle!(\"Inhibitory Population\")\n\nAdd initial guesses to these two plots\n\np3 = plot(1:N_E, gNa_E_true, label=\"True E gNa\", lw=2, color=:black, shape=:circle)\nplot!(p3, 1:N_E, guess_gNa_E, label=\"Init E gNa\", lw=2, color=:steelblue, shape=:utriangle)\nplot!(p3, 1:N_E, opt_gNa_E, label=\"Recovered E gNa\", lw=2, color=:crimson, shape=:square)\ntitle!(\"Heterogeneous gNa Recovery (E Pop)\")\n\np4 = plot(1:N_I, gNa_I_true, label=\"True I gNa\", lw=2, color=:black, shape=:circle)\nplot!(p4, 1:N_I, guess_gNa_I, label=\"Init I gNa\", lw=2, color=:steelblue, shape=:utriangle)\nplot!(p4, 1:N_I, opt_gNa_I, label=\"Recovered I gNa\", lw=2, color=:crimson, shape=:square)\ntitle!(\"Heterogeneous gNa Recovery (I Pop)\")\n\np = plot(p1, p2, p3, p4, layout=(4,1), size=(900, 1000), legend=:outertop)\nxlabel!(p, \"Time (ms) / Neuron Index\")\nylabel!(p, \"V (mV) / Conductance\")\n\np","title":"4. Optimize and Plot"},{"category":"section","location":"examples/14_pem_vectorized_pop/#5.-Comparison-of-scalar-parameters","page":"14 pem vectorized pop","text":"Markdown.parse(\"\"\"\n| Parameter | True Value | Initial Guess | Recovered Value |\n|-----------|------------|---------------|-----------------|\n| E: gK     | $true_gK   | $guess_gK     | $(round(opt_gK_E, digits=3)) |\n| E: gleak  | $true_gleak| $guess_gleak  | $(round(opt_gleak_E, digits=3)) |\n| I: gK     | $true_gK   | $guess_gK     | $(round(opt_gK_I, digits=3)) |\n| I: gleak  | $true_gleak| $guess_gleak  | $(round(opt_gleak_I, digits=3)) |\n\"\"\")\n\n\n\nThis page was generated using Literate.jl.","title":"5. Comparison of scalar parameters"},{"category":"section","location":"examples/10_param_estimation_weight/#Example-10:-Parameter-Estimation-of-a-Synaptic-Weight","page":"10 param estimation weight","text":"using MTKNeuralToolkit\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing ModelingToolkitStandardLibrary.Blocks: Sine\nusing OrdinaryDiffEq\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing Plots","title":"Example 10: Parameter Estimation of a Synaptic Weight"},{"category":"section","location":"examples/10_param_estimation_weight/#Build-the-Network-and-Generate-Target-Data","page":"10 param estimation weight","text":"top = Scalar()\n\nfunction build_neuron(name::Symbol)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top)\n    @named k    = PotassiumChannel(topology=top)\n    @named leak = LeakChannel(topology=top)\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\npre_neuron  = build_neuron(:pre_neuron)\npost_neuron = build_neuron(:post_neuron)\n\ntrue_g_max = 3.0\n@named true_synapse = ExpSynapse(g_max=true_g_max, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\ntrue_synapse_specs = [\n    SynapseSpec(pre_neuron.interfaces.V, post_neuron.interfaces.V,\n                post_neuron.interfaces.I_syn, true_synapse)\n]\n\n@named driver = Sine(amplitude=8.0, frequency=0.05, offset=8.0)\ndrivers = [(1, driver)]\n\ntrue_net = build_acausal_network([pre_neuron, post_neuron];\n                            synapse_specs=true_synapse_specs,\n                            drivers=drivers, name=:true_net)\n\nsys = mtkcompile(true_net.sys)\ntrue_prob = ODEProblem(sys, [], (0.0, 200.0))\n\ntimesteps = 0.0:0.5:200.0\nsol = solve(true_prob, Tsit5(); saveat=timesteps)\ntarget_data = Array(sol)","title":"Build the Network & Generate Target Data"},{"category":"section","location":"examples/10_param_estimation_weight/#Setup-the-Optimization-Problem","page":"10 param estimation weight","text":"guess_g_max = 1.0\n@named fit_synapse = ExpSynapse(g_max=guess_g_max, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nfit_synapse_specs = [\n    SynapseSpec(pre_neuron.interfaces.V, post_neuron.interfaces.V,\n                post_neuron.interfaces.I_syn, fit_synapse)\n]\n\nfit_net = build_acausal_network([pre_neuron, post_neuron];\n                            synapse_specs=fit_synapse_specs,\n                            drivers=drivers, name=:fit_net)\n\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, 200.0))\n\ng_max_sym = fit_sys.fit_synapse.g_max\nsetter = setp(fit_prob, [g_max_sym])\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nfunction loss(x, p)\n    prob, timesteps, data, setter, diffcache = p\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n    setter(ps, x)\n    newprob = remake(prob; p = ps)\n    sol = solve(newprob, Tsit5(); saveat=timesteps)\n    if size(Array(sol)) != size(data)\n        return Inf\n    end\n    return sum(abs2, Array(sol) .- data) / size(data, 2)\nend\n\nopt_params = (fit_prob, timesteps, target_data, setter, diffcache)\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\noptprob = OptimizationProblem(optfn, [guess_g_max], opt_params)","title":"Setup the Optimization Problem"},{"category":"section","location":"examples/10_param_estimation_weight/#Optimize-and-Plot","page":"10 param estimation weight","text":"println(\"Solving with initial guess for visualization...\")\n\nCapture the behavior before optimization to show how far it came\n\ninit_sol = solve(fit_prob, Tsit5(); saveat=timesteps)\n\nprintln(\"Starting optimization to find synaptic weight...\")\nres = solve(optprob, BFGS(); maxiters=200)\n\nprintln(\"True g_max: $true_g_max\")\nprintln(\"Recovered g_max: $(res.u[1])\")\n\nRe-solve with optimized parameters\n\nopt_ps = parameter_values(fit_prob)\nopt_buffer = copy(canonicalize(Tunable(), opt_ps)[1])\nopt_ps = replace(Tunable(), opt_ps, opt_buffer)\nsetter(opt_ps, res.u)\nopt_prob_final = remake(fit_prob; p=opt_ps)\n\nopt_sol = solve(opt_prob_final, Tsit5(); saveat=timesteps)\n\nIn our 2-neuron HH network, the post-synaptic voltage is the 5th state vector element\n\np1 = plot(timesteps, target_data[5, :], label=\"True Post-synaptic V\", lw=2, color=:black)\nplot!(p1, timesteps, init_sol[5, :], label=\"Initial Guess\", ls=:dot, lw=2, color=:gray)\nplot!(p1, timesteps, opt_sol[5, :], label=\"Fitted Post-synaptic V\", ls=:dash, lw=2, color=:red)\ntitle!(p1, \"Parameter Estimation of Synaptic Weight\")\nxlabel!(\"Time (ms)\")\nylabel!(\"V (mV)\")\np1\n\n\n\nThis page was generated using Literate.jl.","title":"Optimize and Plot"},{"category":"section","location":"examples/01b_first_principles_HH/#Building-Custom-Ion-Channels-from-Scratch","page":"01b first principles HH","text":"In Example 1, we used GateSpec and GenericChannel to build a Hodgkin-Huxley neuron in just a few lines of code. But what if you need a channel that doesn't fit the standard alpha/beta gating paradigm? What if you want to implement a complex Markov chain model, or non-standard biophysics?\n\nGenericChannel isn't a black box—it's just a convenience wrapper around standard ModelingToolkit components.\n\nThe only rule for an ion channel in this toolkit is that it must be an MTK system that extends a standard electrical OnePort. Let's prove it by building a custom leak channel and a custom persistent sodium channel (NaP) from first principles.\n\nnote: Extending Synapses\nSynapses are very similar. You can look at the source code for e.g., exponential synapses and extend them similarly.\n\n\n\nusing MTKNeuralToolkit\nusing ModelingToolkit: mtkcompile, @named, @variables, @parameters, t_nounits as t, D_nounits as D, extend, @component, @unpack, System\nusing ModelingToolkitStandardLibrary.Electrical: OnePort\nusing OrdinaryDiffEq\nusing Plots","title":"Building Custom Ion Channels from Scratch"},{"category":"section","location":"examples/01b_first_principles_HH/#1.-A-Custom-Leak-Channel","page":"01b first principles HH","text":"A leak channel has no states; it simply follows Ohm's law:\n\nI = g(V - E)\n\nWe define it as an MTK @component that wraps an OnePort. The steps are:\n\nInstantiate the OnePort to get the voltage v and current i.\nDefine parameters g and E_rev.\nWrite the governing equation.\nExtend the OnePort with our equations. This tells MTK that our component behaves as an electrical OnePort, which is exactly what build_compartment expects.\n\n@component function CustomLeakChannel(; name, g=0.3, E_rev=-54.4)\n    @named oneport = OnePort()\n    @unpack v, i = oneport\n    @parameters g=g E_rev=E_rev\n    eqs = [i ~ g * (v - E_rev)]\n    return extend(System(eqs, t, [], [g, E_rev]; name=name), oneport)\nend\n\n","title":"1. A Custom Leak Channel"},{"category":"section","location":"examples/01b_first_principles_HH/#2.-A-Custom-Persistent-Sodium-Channel-(NaP)","page":"01b first principles HH","text":"Let's build a channel with a single gating variable, m, that does not inactivate (persistent). We'll use a custom steady-state function and a time constant, writing out the ODE manually.\n\nThe gating ODE is:\n\nfracdmdt = fracm_infty - mtau\n\nAnd the current equation is:\n\nI = g cdot m^p cdot (V - E)\n\nLet's use p=1 for NaP. We initialize the state variable m based on V_init.\n\n@component function CustomNaPChannel(; name, g=10.0, E_rev=50.0, V_init=-65.0)\n    @named oneport = OnePort()\n    @unpack v, i = oneport\n\n    @parameters g=g E_rev=E_rev\n    @variables m(t) = 1.0 / (1.0 + exp(-(V_init + 50.0) / 5.0))\n\n    m_inf(V) = 1.0 / (1.0 + exp(-(V + 50.0) / 5.0))\n    tau_m = 5.0\n\n    eqs = [\n        D(m) ~ (m_inf(v) - m) / tau_m,\n        i ~ g * m * (v - E_rev)\n    ]\n\n    return extend(System(eqs, t, [m], [g, E_rev]; name=name), oneport)\nend\n\n","title":"2. A Custom Persistent Sodium Channel (NaP)"},{"category":"section","location":"examples/01b_first_principles_HH/#3.-Assemble-the-Compartment","page":"01b first principles HH","text":"We instantiate our custom channels and a standard Capacitor. Note that build_compartment doesn't know or care that these are custom; it just connects their positive pins to the membrane voltage and grounds the negative pins.\n\ntop = Scalar() # Define a scalar topology\n\n@named cap = Capacitor(topology=top, C=1.0)\n@named leak = CustomLeakChannel()\n@named nap = CustomNaPChannel()\n\nbuild_compartment handles the wiring just like in Example 1.\n\nchannels = [leak, nap]\nsoma = build_compartment(cap, channels; name=:soma, V_init=-65.0, topology=top)\n\n","title":"3. Assemble the Compartment"},{"category":"section","location":"examples/01b_first_principles_HH/#4.-Build-and-Simulate","page":"01b first principles HH","text":"We'll inject a small current to see how the persistent sodium channel interacts with the leak channel to create a steady depolarized state.\n\ndrivers = [(1, 2.0)]\nnet = build_acausal_network([soma]; drivers=drivers, name=:custom_neuron)\n\nprintln(\"Compiling custom channel neuron...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 100.0))\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23(), reltol=1e-4, abstol=1e-4)\n\n","title":"4. Build and Simulate"},{"category":"section","location":"examples/01b_first_principles_HH/#5.-Plot-the-Results","page":"01b first principles HH","text":"We can access the variables of our custom components exactly as we would with the pre-built channels, reaching into the compiled system's namespace.\n\np1 = plot(sol, idxs=[sys.soma.cap.v],\n          title=\"Example 0: Custom Channel Voltage\",\n          ylabel=\"V (mV)\", legend=false)\n\nLook at the gating variable m of our custom NaP channel!\n\np2 = plot(sol, idxs=[sys.soma.nap.m],\n          title=\"Custom NaP Gating Variable (m)\",\n          ylabel=\"Fraction open\", xlabel=\"Time (ms)\", legend=false)\n\nplot(p1, p2, layout=(2,1), size=(800, 600))\n\nOK... nobody said it was going to be an interesting channel!\n\n\n\nThis page was generated using Literate.jl.","title":"5. Plot the Results"},{"category":"section","location":"examples/05_mixed_topologies/#Example-5:-Mixed-Topologies-(Scalar-Hub-and-Vectorized-Populations)","page":"05 mixed topologies","text":"This example demonstrates the flexibility of MTKNeuralToolkit's symbolic interfaces. You can seamlessly mix Scalar and Vectorized topologies in the same network. Because vectorized compartments expose their states as symbolic arrays, you can directly index into them (e.g., pop.interfaces.V[1]) to wire up standard scalar synapses to specific elements of a population.\n\nWe create a \"hub\" neuron (Scalar) that interacts with an E/I population pair (Vectorized). The hub excites the first neuron of the E-pop, which inhibits the hub. The E-pop also projects densely to the I-pop using a weight matrix.\n\n\n\nusing MTKNeuralToolkit\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing ModelingToolkitStandardLibrary.Blocks: Sine\nusing OrdinaryDiffEq\nusing Plots","title":"Example 5: Mixed Topologies (Scalar Hub and Vectorized Populations)"},{"category":"section","location":"examples/05_mixed_topologies/#1.-Build-the-Scalar-\"Hub\"-Neuron","page":"05 mixed topologies","text":"top_scalar = Scalar()\n\nfunction build_hh_neuron(name::Symbol)\n    @named cap  = Capacitor(topology=top_scalar, C=1.0)\n    @named na   = SodiumChannel(topology=top_scalar)\n    @named k    = PotassiumChannel(topology=top_scalar)\n    @named leak = LeakChannel(topology=top_scalar)\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top_scalar)\nend\n\nhub_neuron = build_hh_neuron(:hub_neuron)\n\n","title":"1. Build the Scalar \"Hub\" Neuron"},{"category":"section","location":"examples/05_mixed_topologies/#2.-Build-the-Vectorized-Populations-(E-and-I)","page":"05 mixed topologies","text":"N_E = 5\nN_I = 3\ntop_E = Vectorized(N_E)\ntop_I = Vectorized(N_I)\n\nfunction build_vector_pop(name::Symbol, top)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top)\n    @named k    = PotassiumChannel(topology=top)\n    @named leak = LeakChannel(topology=top)\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\npop_E = build_vector_pop(:pop_E, top_E)\npop_I = build_vector_pop(:pop_I, top_I)\n\n","title":"2. Build the Vectorized Populations (E and I)"},{"category":"section","location":"examples/05_mixed_topologies/#3.-Wire-Synapses","page":"05 mixed topologies","text":"","title":"3. Wire Synapses"},{"category":"section","location":"examples/05_mixed_topologies/#A.-Mixed-Topology-(Scalar-Vectorized)","page":"05 mixed topologies","text":"The scalar hub excites the FIRST neuron in popE, and popE[1] inhibits the hub.\n\n@named syn_hub_to_E = ExpSynapse(g_max=3.0, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n@named syn_E_to_hub = ExpSynapse(g_max=5.0, τ=5.0, E_rev=-80.0, V_th=-20.0, slope=2.0)","title":"A. Mixed Topology (Scalar <-> Vectorized)"},{"category":"section","location":"examples/05_mixed_topologies/#B.-Vectorized-Vectorized","page":"05 mixed topologies","text":"popE projects densely to popI using a weight matrix\n\nW_EI = 0.5 .* rand(N_I, N_E)\nsyn_EI = build_synapse_block(pop_E, pop_I, W_EI; name=:syn_EI, E_rev=0.0)\n\nsynapse_specs = [\n    #Hub -> pop_E[1]\n    SynapseSpec(hub_neuron.interfaces.V, pop_E.interfaces.V[1], pop_E.interfaces.I_syn[1], syn_hub_to_E),\n    # pop_E[1] -> Hub\n    SynapseSpec(pop_E.interfaces.V[1], hub_neuron.interfaces.V, hub_neuron.interfaces.I_syn, syn_E_to_hub),\n    #pop_E -> pop_I (Vectorized block)\n    syn_EI\n]\n\n","title":"B. Vectorized <-> Vectorized"},{"category":"section","location":"examples/05_mixed_topologies/#4.-Driving-Stimuli-and-Network-Assembly","page":"05 mixed topologies","text":"Drive the hub neuron with a steady current to keep it spiking\n\n@named current_driver = Sine(amplitude=8.0, frequency=0.05, offset=8.0)\ndrivers = [(1, current_driver)]\n\nnote: Automatic Grounding\nThe network builder handles all grounding implicitly. Undriven elements in popE and popI will be grounded automatically.\n\nnet = build_acausal_network([hub_neuron, pop_E, pop_I];\n                            synapse_specs=synapse_specs,\n                            drivers=drivers,\n                            name=:mixed_net)\n\nprintln(\"Compiling mixed-topology network...\")\nsys = mtkcompile(net.sys)\n\nMixed systems generate block-diagonal Jacobians, so sparse solvers excel here.\n\nprob = ODEProblem(sys, [], (0.0, 200.0), jac=true, sparse=true)\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23())\n\n","title":"4. Driving Stimuli & Network Assembly"},{"category":"section","location":"examples/05_mixed_topologies/#5.-Plot-the-Results","page":"05 mixed topologies","text":"p1 = plot(sol, idxs=[sys.hub_neuron.cap.v],\n          title=\"Scalar Hub Neuron\", ylabel=\"V (mV)\", legend=false)\n\np2 = plot(sol, idxs=[sys.pop_E.cap.v...],\n          title=\"Excitatory Pop (Pop[1] synapsed)\", ylabel=\"V (mV)\", legend=false)\n\np3 = plot(sol, idxs=[sys.pop_I.cap.v...],\n          title=\"Inhibitory Pop (Driven by E)\", ylabel=\"V (mV)\", xlabel=\"Time (ms)\", legend=false)\n\nplot(p1, p2, p3, layout=(3,1), size=(800, 600))\n\n\n\nThis page was generated using Literate.jl.","title":"5. Plot the Results"},{"category":"section","location":"examples/07_calcium_gates/#Example-7:-Calcium-Dynamics-and-Nernst-Potentials","page":"07 calcium gates","text":"This example introduces the Calcium dynamics machinery of MTKNeuralToolkit. Real neurons maintain low intracellular Calcium, but voltage-gated Calcium channels (CaV) allow Calcium ions to flow in during spikes. This influx is tracked by a CalciumTracker pool, which slowly decays back to baseline.\n\nCrucially, CaVChannel does not use a fixed reversal potential. It dynamically calculates the Calcium Nernst potential based on the current intracellular Calcium concentration. We also include a Calcium-activated potassium channel (KCa) which uses the Calcium pool to modulate its gating.\n\nusing MTKNeuralToolkit\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing Plots","title":"Example 7: Calcium Dynamics & Nernst Potentials"},{"category":"section","location":"examples/07_calcium_gates/#Define-Gating-Dynamics","page":"07 calcium gates","text":"We use standard HH gates for Na and K (fast spiking)\n\nhh_na_m = v -> (\n    0.1 .* (v .+ 40.0) ./ (1.0 .- exp.(-(v .+ 40.0) ./ 10.0)),\n    4.0 .* exp.(-(v .+ 65.0) ./ 18.0)\n)\nhh_na_h = v -> (\n    0.07 .* exp.(-(v .+ 65.0) ./ 20.0),\n    1.0 ./ (1.0 .+ exp.(-(v .+ 35.0) ./ 10.0))\n)\nsodium_gates = [GateSpec(:m, 3, 0.052, hh_na_m), GateSpec(:h, 1, 0.596, hh_na_h)]\n\nhh_k_n = v -> (\n    0.01 .* (v .+ 55.0) ./ (1.0 .- exp.(-(v .+ 55.0) ./ 10.0)),\n    0.125 .* exp.(-(v .+ 65.0) ./ 80.0)\n)\npotassium_gates = [GateSpec(:n, 4, 0.317, hh_k_n)]\n\nDefine a simple CaV channel gate using InfTau\n\nCaV_m_inf(v) = 1.0 ./ (1.0 .+ exp.(-(v .+ 20.0) ./ 5.0))\nCaV_tau_m(v) = 5.0 .+ 10.0 ./ (1.0 .+ exp.((v .+ 20.0) ./ 10.0))\nCaV_dynamics = InfTau(CaV_m_inf, CaV_tau_m)\ncav_gates = [GateSpec(:mCaV, 3, 0.0, CaV_dynamics)]\n\nDefine a KCa channel gate. It depends on BOTH voltage and Calcium! Note the two arguments: (v, ca). We use the InfTauCa helper for this.\n\nKCa_m_inf(v, ca) = (ca ./ (ca .+ 3.0)) ./ (1.0 .+ exp.(-(v .+ 20.0) ./ 5.0))\nKCa_tau_m(v) = 20\nKCa_dynamics = InfTauCa(KCa_m_inf, KCa_tau_m)\nkca_gates = [GateSpec(:mKCa, 4, 0.0, KCa_dynamics)]","title":"Define Gating Dynamics"},{"category":"section","location":"examples/07_calcium_gates/#Build-the-Compartment","page":"07 calcium gates","text":"top = Scalar()\n\nStandard channels\n\n@named cap = Capacitor(topology=top, C=1.0)\n@named na  = GenericChannel(topology=top, g=100.0, E_rev=50.0,  gates=sodium_gates)\n@named k   = GenericChannel(topology=top, g=36.0,  E_rev=-77.0, gates=potassium_gates)\n@named leak= GenericChannel(topology=top, g=0.3,   E_rev=-54.4, gates=GateSpec[])\n\nCalcium channel. Note we don't pass Erev! We pass Caout and nernstfactor. nernstfactor = (RT)/(zF) ~ 13.0 at room temp for natural log. The conversion_factor scales the current into a Ca2+ concentration rate.\n\n@named cav = CaVChannel(topology=top, g=2.0, gates=cav_gates, Ca_out=3000.0,\n                        nernst_factor=13.0, conversion_factor=0.047)\n\nKCa channel\n\n@named kca = KCaChannel(topology=top, g=5.0, E_rev=-80.0, gates=kca_gates)\n\nCalcium Tracker: sets the baseline intracellular Ca and the decay rate\n\nion_config = CalciumTracker(decay=200.0, Ca_init=0.05)\n\nneuron = build_compartment(cap, [na, k, leak, cav, kca];\n                           name=:neuron,\n                           V_init=-65.0,\n                           topology=top,\n                           ion_config=ion_config)","title":"Build the Compartment"},{"category":"section","location":"examples/07_calcium_gates/#Build-and-Simulate-the-Network","page":"07 calcium gates","text":"drivers = [(1, 15.0)] # Current to elicit spikes and Calcium transients\nnet = build_acausal_network([neuron]; drivers=drivers, name=:ca_neuron)\n\nprintln(\"Compiling Calcium neuron...\")\nsys = mtkcompile(net.sys)\nprob = ODEProblem(sys, [], (0.0, 800.0), jac=true, sparse=true)\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23(), reltol=1e-4, abstol=1e-4)","title":"Build and Simulate the Network"},{"category":"section","location":"examples/07_calcium_gates/#Plot-the-Results","page":"07 calcium gates","text":"Let's look at the voltage, the dynamic Calcium concentration, and the KCa current.\n\np1 = plot(sol, idxs=[sys.neuron.cap.v], title=\"Membrane Potential\", ylabel=\"V (mV)\", legend=false)\n\nAccess the internal calcium pool. The CalciumTracker creates a system named <compartment_name>_ca_pool, which contains the Ca variable.\n\np2 = plot(sol, idxs=[sys.neuron.neuron_ca_pool.Ca], title=\"Intracellular Calcium\", ylabel=\"[Ca] (uM)\", legend=false)\n\np3 = plot(sol, idxs=[sys.neuron.kca.i], title=\"KCa Current\", ylabel=\"I (mA)\", xlabel=\"Time (ms)\", legend=false)\n\nplot(p1, p2, p3, layout=(3,1), size=(800, 900))\n\n\n\nThis page was generated using Literate.jl.","title":"Plot the Results"},{"category":"section","location":"examples/04_vectorized_dynamics/#Example-4:-Vectorized-Populations-(E/I-Network)","page":"04 vectorized dynamics","text":"Let's scale up to population-level models. Instead of building thousands of individual scalar systems, we can use the Vectorized topology. A single GenericChannel with a vectorized topology expands to N elements. We wire dense excitatory/inhibitory populations together using a weight matrix and the build_synapse_block helper.\n\nThe main benefit of the Vectorized topology is that it saves compile time. Compiling 1,000 scalar systems requires MTK to process 1,000 separate symbolic graphs. Using Vectorized(1000) collapses the entire population into a single system that uses array operations.\n\nnote: Note\nAn annoyance is the need to build both scalar and vector definitions for the components. It would be nice (and maybe exists?) for MTK to have some automatic way of turning a scalar component into a vectorised one? I spent some time attempting this with postwalk, and got it running. But it was messy and dependent on the MTK internal API so decided to demand a separate set of equations for a vectorised component.\n\nusing MTKNeuralToolkit, Random\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing Plots","title":"Example 4: Vectorized Populations (E/I Network)"},{"category":"section","location":"examples/04_vectorized_dynamics/#1.-Define-Shared-Gating-Dynamics","page":"04 vectorized dynamics","text":"These functions use broadcasting (.) so they work identically for both scalar and vectorized topologies.\n\nhh_na_m = v -> (\n    0.182 .* (v .+ 35.0) ./ (1.0 .- exp.(-(v .+ 35.0) ./ 9.0)),\n    -0.124 .* (v .+ 35.0) ./ (1.0 .- exp.((v .+ 35.0) ./ 9.0))\n)\nhh_na_h = v -> (\n    0.25 .* exp.(-(v .+ 90.0) ./ 12.0),\n    0.25 .* (exp.((v .+ 62.0) ./ 6.0)) ./ exp.(-(v .+ 90.0) ./ 12.0)\n)\nsodium_gates = [GateSpec(:m, 3, 0.0, hh_na_m), GateSpec(:h, 1, 0.0, hh_na_h)]\n\nhh_k_n = v -> (\n    0.02 .* (v .- 25.0) ./ (1.0 .- exp.(-(v .- 25.0) ./ 9.0)),\n    -0.002 .* (v .- 25.0) ./ (1.0 .- exp.((v .- 25.0) ./ 9.0))\n)\npotassium_gates = [GateSpec(:n, 4, 0.0, hh_k_n)]","title":"1. Define Shared Gating Dynamics"},{"category":"section","location":"examples/04_vectorized_dynamics/#2.-Define-Topologies-and-Build-Populations","page":"04 vectorized dynamics","text":"N_E = 15\nN_I = 5\ntop_E = Vectorized(N_E)\ntop_I = Vectorized(N_I)\n\nLet's make the sodium conductance heterogeneous across the population\n\nfunction build_population(name::Symbol, top)\n    gNa_heterogeneous = collect(range(119.0, 121.0, length=top.N))\n\n    @named cap = Capacitor(topology=top, C=1.0)\n    @named na  = GenericChannel(topology=top, g=gNa_heterogeneous, E_rev=50.0,  gates=sodium_gates)\n    @named k   = GenericChannel(topology=top, g=36.0,  E_rev=-77.0, gates=potassium_gates)\n    @named leak= GenericChannel(topology=top, g=0.3,   E_rev=-54.4, gates=GateSpec[])\n\n    return build_compartment(cap, [na, k, leak]; name=name, V_init=-65.0, topology=top)\nend\n\npop_E = build_population(:pop_E, top_E)\npop_I = build_population(:pop_I, top_I)","title":"2. Define Topologies and Build Populations"},{"category":"section","location":"examples/04_vectorized_dynamics/#3.-Define-Connectivity-Matrices","page":"04 vectorized dynamics","text":"The weight matrix W maps presynaptic populations to postsynaptic populations. Dimensions must be (Npost, Npre).\n\nRandom.seed!(42)\nW_EE = 0.5 .* rand(N_E, N_E)\nW_EI = 1.0 .* rand(N_I, N_E)\nW_IE = 2.0 .* rand(N_E, N_I)\nW_II = 1.0 .* rand(N_I, N_I)","title":"3. Define Connectivity Matrices"},{"category":"section","location":"examples/04_vectorized_dynamics/#4.-Build-Synapse-Blocks","page":"04 vectorized dynamics","text":"build_synapse_block sets up the vectorized synapse matrices and creates the SynapseSpecs for the network builder.\n\nsyn_EE = build_synapse_block(pop_E, pop_E, W_EE; name=:syn_EE, E_rev=0.0)\nsyn_EI = build_synapse_block(pop_E, pop_I, W_EI; name=:syn_EI, E_rev=0.0)\nsyn_IE = build_synapse_block(pop_I, pop_E, W_IE; name=:syn_IE, E_rev=-80.0)\nsyn_II = build_synapse_block(pop_I, pop_I, W_II; name=:syn_II, E_rev=-80.0)\n\nsynapse_specs = [syn_EE, syn_EI, syn_IE, syn_II]","title":"4. Build Synapse Blocks"},{"category":"section","location":"examples/04_vectorized_dynamics/#5.-Driving-Stimuli-and-Network-Assembly","page":"04 vectorized dynamics","text":"Give the excitatory population a constant current kick to start the activity\n\ndrivers = [(1, 15.0)]\n\nnet = build_acausal_network([pop_E, pop_I]; synapse_specs=synapse_specs, drivers=drivers)\n\nprintln(\"Compiling vectorized network...\")\nsys = mtkcompile(net.sys)\n\nBecause the underlying equations are array-based, the Jacobian of this system is highly sparse: most neurons only affect their own gating variables, with off-diagonal elements coming only from the synapse blocks.\n\nPassing jac=true, sparse=true tells the solver to compute an analytical Jacobian and leverage sparse linear algebra. This speeds simulation, as the solver only computes non-zero derivatives instead of a dense matrix. Sparse Jacobians are also essential for fast automatic differentiation (AD), which we will need later for parameter estimation.\n\nprob = ODEProblem(sys, [], (0.0, 100.0), jac=true, sparse=true)\n\nLet's visualize the sparsity pattern using Plots.spy. You'll see a heavy block-diagonal structure (intrinsic dynamics) with off-diagonal bands representing the synaptic couplings between the E and I populations.\n\nprintln(\"Plotting Jacobian sparsity pattern...\")\nspy(prob.f.jac_prototype,\n     title=\"Jacobian Sparsity Pattern\",\n     xlabel=\"Column (Equation Index)\",\n     ylabel=\"Row (Variable Index)\",\n     size=(600, 600))\n\n\nprintln(\"Solving...\")\nsol = solve(prob, Rosenbrock23())","title":"5. Driving Stimuli & Network Assembly"},{"category":"section","location":"examples/04_vectorized_dynamics/#6.-Plot-the-Results","page":"04 vectorized dynamics","text":"We splat the voltage array (...) to plot all individual elements in the population. Couldn't find a way to add numberings with MTK but I assume it exists...?\n\np1 = plot(sol, idxs=[sys.pop_E.cap.v...],\n          title=\"Excitatory Population\", legend=true, ylabel=\"V (mV)\")\np2 = plot(sol, idxs=[sys.pop_I.cap.v...],\n          title=\"Inhibitory Population\", legend=false, ylabel=\"V (mV)\", xlabel=\"Time (ms)\")\n\nCombine the simulation plots with the sparsity plot\n\nplot(p1, p2, layout=(2,1), size=(800, 800))\n\n\n\nThis page was generated using Literate.jl.","title":"6. Plot the Results"},{"category":"section","location":"examples/08_stg_network/#Example-8:-Stomatogastric-Ganglion-(STG)-Network","page":"08 stg network","text":"This example reconstructs a simplified 3-neuron network (AB, LP, PY) based on the classic stomatogastric ganglion models (e.g., Prinz et al., 2004). It demonstrates the use of Calcium channels, Calcium trackers, custom geometries, and multiple synapse types (Cholinergic and Glutamatergic) in a single network.\n\nusing MTKNeuralToolkit\nusing MTKNeuralToolkit.PrinzNeuron\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq, Plots","title":"Example 8: Stomatogastric Ganglion (STG) Network"},{"category":"section","location":"examples/08_stg_network/#Network-Parameters-and-Geometry","page":"08 stg network","text":"Prinz uses a custom geometry to scale capacitance, conductances, and calcium flow. We instantiate it here and define shared Calcium parameters. Note that the custom geometry occupies < 10 lines of code in the src/library/PrinzCalciumNeuron.jl file. Geometries are easy to make.\n\nconst geom = PrinzGeometry(area=0.0628, C_m=10.0)\nconst tauCa = 200.0\nconst Ca_inf = 0.05\nconst prinz_ion_config = CalciumTracker(decay=ca -> (Ca_inf .- ca) ./ tauCa, Ca_init=Ca_inf)\nconst nernst_factor = 500.0 * 8.6174e-5 * 283.15","title":"Network Parameters & Geometry"},{"category":"section","location":"examples/08_stg_network/#Local-Channel-Builders","page":"08 stg network","text":"We use closures to neatly attach the geometry, reversal potentials, and tauCa to the pre-built Prinz gate definitions. This keeps the neuron builder clean.\n\nNaCh(g; name)   = GenericChannel(name=name, g=g, E_rev=50.0, gates=PrinzNeuron.na_gates, geometry=geom)\nCaSCh(g; name)  = CaVChannel(name=name, g=g, gates=PrinzNeuron.cas_gates, Ca_out=3000.0,\n                             nernst_factor=nernst_factor, geometry=geom, tauCa=tauCa)\nCaTCh(g; name)  = CaVChannel(name=name, g=g, gates=PrinzNeuron.cat_gates, Ca_out=3000.0,\n                             nernst_factor=nernst_factor, geometry=geom, tauCa=tauCa)\nHCh(g; name)    = GenericChannel(name=name, g=g, E_rev=-20.0, gates=PrinzNeuron.h_gates, geometry=geom)\nKaCh(g; name)   = GenericChannel(name=name, g=g, E_rev=-80.0, gates=PrinzNeuron.ka_gates, geometry=geom)\nKCaCh(g; name)  = KCaChannel(name=name, g=g, E_rev=-80.0, gates=PrinzNeuron.kca_gates, geometry=geom)\nKdrCh(g; name)  = GenericChannel(name=name, g=g, E_rev=-80.0, gates=PrinzNeuron.kdr_gates, geometry=geom)\nLeakCh(g; name) = GenericChannel(name=name, g=g, E_rev=-50.0, gates=GateSpec[], geometry=geom)","title":"Local Channel Builders"},{"category":"section","location":"examples/08_stg_network/#Build-Neurons","page":"08 stg network","text":"function build_AB()\n    @named cap  = Capacitor(geometry=geom)\n    @named na   = NaCh(100.0); @named cas  = CaSCh(6.0);  @named cat = CaTCh(2.5)\n    @named h    = HCh(0.01);   @named ka   = KaCh(50.0);  @named kca = KCaCh(5.0)\n    @named kdr  = KdrCh(100.0)\n    return build_compartment(cap, [na, cas, cat, h, ka, kca, kdr];\n                             name=:AB, V_init=-60.0, ion_config=prinz_ion_config)\nend\n\nfunction build_PY()\n    @named cap  = Capacitor(geometry=geom)\n    @named na   = NaCh(100.0); @named cas  = CaSCh(2.0);  @named cat = CaTCh(2.4)\n    @named h    = HCh(0.05);   @named ka   = KaCh(50.0);  @named kdr = KdrCh(125.0)\n    @named leak = LeakCh(0.01)\n    return build_compartment(cap, [na, cas, cat, h, ka, kdr, leak];\n                             name=:PY, V_init=-55.0, ion_config=prinz_ion_config)\nend\n\nfunction build_LP()\n    @named cap  = Capacitor(geometry=geom)\n    @named na   = NaCh(100.0); @named cas  = CaSCh(4.0)\n    @named h    = HCh(0.05);   @named ka   = KaCh(20.0);  @named kdr = KdrCh(25.0)\n    @named leak = LeakCh(0.03)\n    return build_compartment(cap, [na, cas, h, ka, kdr, leak];\n                             name=:LP, V_init=-65.0, ion_config=prinz_ion_config)\nend\n\nAssign to variables so STG_synapses() can reference them in the global scope\n\nAB = build_AB()\nPY = build_PY()\nLP = build_LP()\n\nneurons = [AB, PY, LP]","title":"Build Neurons"},{"category":"section","location":"examples/08_stg_network/#Define-Synapses-and-Network","page":"08 stg network","text":"function STG_synapses()\n    @named ABLP_chol = CholSynapse(g_max=30.0, geometry=geom)\n    @named ABPY_chol = CholSynapse(g_max=3.0 , geometry=geom)\n    @named ABLP_glut = GlutSynapse(g_max=30.0, geometry=geom)\n    @named ABPY_glut = GlutSynapse(g_max=10.0, geometry=geom)\n    @named LPAB_glut = GlutSynapse(g_max=30.0, geometry=geom)\n    @named LPPY_glut = GlutSynapse(g_max=1.0 , geometry=geom)\n    @named PYLP_glut = GlutSynapse(g_max=30.0, geometry=geom)\n\n    return [\n        SynapseSpec(LP.interfaces.V, AB.interfaces.V, AB.interfaces.I_syn, LPAB_glut),\n        SynapseSpec(AB.interfaces.V, PY.interfaces.V, PY.interfaces.I_syn, ABPY_chol),\n        SynapseSpec(AB.interfaces.V, PY.interfaces.V, PY.interfaces.I_syn, ABPY_glut),\n        SynapseSpec(LP.interfaces.V, PY.interfaces.V, PY.interfaces.I_syn, LPPY_glut),\n        SynapseSpec(AB.interfaces.V, LP.interfaces.V, LP.interfaces.I_syn, ABLP_chol),\n        SynapseSpec(AB.interfaces.V, LP.interfaces.V, LP.interfaces.I_syn, ABLP_glut),\n        SynapseSpec(PY.interfaces.V, LP.interfaces.V, LP.interfaces.I_syn, PYLP_glut)\n    ]\nend\n\nnet = build_acausal_network(neurons; synapse_specs=STG_synapses(), name=:stg)\nprintln(\"Compiling STG network...\")\nsys = mtkcompile(net.sys)","title":"Define Synapses & Network"},{"category":"section","location":"examples/08_stg_network/#Simulate-and-Plot","page":"08 stg network","text":"STG networks often need a few seconds to settle into their characteristic alternating rhythm (pyloric rhythm). We simulate for 3000 ms.\n\ntspan = (0.0, 10000.0)\nprob = ODEProblem(sys, [], tspan, jac=true, sparse=true)\n\nprintln(\"Solving STG network...\")\nsol = solve(prob, Rosenbrock23())\n\np1 = plot(sol, idxs=[sys.AB.cap.v], title=\"AB Neuron\", legend=false, ylabel=\"V (mV)\")\np2 = plot(sol, idxs=[sys.LP.cap.v], title=\"LP Neuron\", legend=false, ylabel=\"V (mV)\")\np3 = plot(sol, idxs=[sys.PY.cap.v], title=\"PY Neuron\", legend=false, ylabel=\"V (mV)\", xlabel=\"Time (ms)\")\n\nplot(p1, p2, p3, layout=(3,1), size=(800,600))\n\n\n\nThis page was generated using Literate.jl.","title":"Simulate & Plot"},{"category":"section","location":"#MTKNeuralToolkit","page":"Home","text":"Documentation for MTKNeuralToolkit.\n\n","title":"MTKNeuralToolkit"},{"category":"type","location":"#MTKNeuralToolkit.CalciumTracker","page":"Home","text":"CalciumTracker\n\nA configuration struct enabling Calcium dynamics within a compartment. When passed to build_compartment, it instantiates a CalciumPool and connects it to all  channels that expose a ca_port.\n\nFields\n\ndecay::Union{Float64, Function}: Either a time constant for linear decay, or a function  that takes the current Calcium concentration and returns the decay rate.\nCa_init::Float64: The initial intracellular Calcium concentration.\n\n\n\n\n\n","title":"MTKNeuralToolkit.CalciumTracker"},{"category":"method","location":"#MTKNeuralToolkit.CalciumTracker-Tuple{}","page":"Home","text":"Keyword argument constructor for CalciumTracker.\n\n\n\n\n\n","title":"MTKNeuralToolkit.CalciumTracker"},{"category":"type","location":"#MTKNeuralToolkit.Compartment","page":"Home","text":"Compartment\n\nA struct representing a single neural compartment (e.g., a soma, axon hillock, or dendritic segment). It wraps the generated ModelingToolkit System along with metadata about its physical and  electrical properties, and exposes a tuple of interfaces for acausal network connections.\n\nFields\n\nsys::System: The underlying MTK system representing the compartment's equations.\ninterfaces::NamedTuple: Exposed boundary variables and pins (e.g., V, p_pin, n_pin, I_ext, I_syn).\nV_init::F: The initial membrane voltage.\ntopology::Union{Scalar, Vectorized}: The electrical topology of the compartment.\ngeometry::G: The physical geometry used for scaling biophysical parameters.\nmorphology::M: The spatial morphology used for rendering or spatial simulations.\n\n\n\n\n\n","title":"MTKNeuralToolkit.Compartment"},{"category":"type","location":"#MTKNeuralToolkit.CouplingSpec","page":"Home","text":"CouplingSpec\n\nA specification struct used to wire an acausal coupling (e.g., a Gap Junction) between two compartments.\n\nFields\n\ncomp_i::Compartment: The first compartment to be coupled.\ncomp_j::Compartment: The second compartment to be coupled.\ncoupling::System: The MTK coupling system component (e.g., GapJunction).\n\n\n\n\n\n","title":"MTKNeuralToolkit.CouplingSpec"},{"category":"type","location":"#MTKNeuralToolkit.Network","page":"Home","text":"Network\n\nA struct representing the complete assembled neural network. It encapsulates the fully  connected MTK System and a vector of input variables for simulation drivers.\n\nFields\n\nsys::System: The final compiled MTK system representing the entire network.\ninputs::Vector{Any}: A collection of symbolic input variables for external stimulation.\n\n\n\n\n\n","title":"MTKNeuralToolkit.Network"},{"category":"type","location":"#MTKNeuralToolkit.NoCalcium","page":"Home","text":"NoCalcium\n\nA configuration struct indicating that a compartment has no Calcium dynamics. When passed to build_compartment, it bypasses the creation of a CalciumPool.\n\n\n\n\n\n","title":"MTKNeuralToolkit.NoCalcium"},{"category":"type","location":"#MTKNeuralToolkit.SynapseSpec","page":"Home","text":"SynapseSpec\n\nA specification struct used to wire a synapse between a presynaptic voltage and a postsynaptic current. It provides the mapping needed by wire_synapses! to inject currents into the correct compartments.\n\nFields\n\npre_V: The symbolic voltage variable of the presynaptic compartment.\npost_V: The symbolic voltage variable of the postsynaptic compartment.\npost_I_syn: The symbolic current variable of the postsynaptic compartment where the synapse will inject.\nsynapse::System: The MTK synapse system component (e.g., ExpSynapse, CholSynapse).\npost_comp::Union{Compartment, Nothing}: The postsynaptic compartment struct (used for block synapse grounding logic).\n\n\n\n\n\n","title":"MTKNeuralToolkit.SynapseSpec"},{"category":"method","location":"#MTKNeuralToolkit.SynapseSpec-NTuple{4, Any}","page":"Home","text":"Outer constructor for SynapseSpec that defaults post_comp to nothing. Useful for scalar synapses where block grounding logic is not required.\n\n\n\n\n\n","title":"MTKNeuralToolkit.SynapseSpec"},{"category":"method","location":"#MTKNeuralToolkit.AlphaSynapse-Tuple{}","page":"Home","text":"AlphaSynapse(; name, g_max=1.0, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nAn alpha-function synapse implemented via a cascade of two first-order filters (s1 and s2).  This produces the classic unimodal alpha-function response in synaptic conductance following  a sustained presynaptic depolarization.\n\nThe current injected into the postsynaptic compartment is: I_syn = g_max * s2 * (E_rev - V_post)\n\nArguments\n\ng_max: Maximum synaptic conductance.\nτ: Time constant for both cascaded filters.\nE_rev: Reversal potential of the synapse.\nV_th: Threshold voltage for presynaptic activation.\nslope: Slope of the presynaptic sigmoid activation.\n\n\n\n\n\n","title":"MTKNeuralToolkit.AlphaSynapse"},{"category":"method","location":"#MTKNeuralToolkit.CholSynapse-Tuple{}","page":"Home","text":"CholSynapse(; name, g_max=30.0, E_rev=-80.0, k_minus=0.01, V_th=-35.0, delta=5.0, geometry=NoGeometry())\n\nA continuous cholinergic synapse model. The synaptic state variable s represents  the fraction of open receptors. It rises towards a steady-state s_inf governed by  the presynaptic voltage, and decays exponentially.\n\nThe synaptic current is calculated as the current injected into the postsynaptic membrane: I_syn = g_max * s * (E_rev - V_post)\n\nArguments\n\ng_max: Maximum synaptic conductance (scaled by geometry if provided).\nE_rev: Reversal potential of the synapse (e.g., -80 mV for inhibitory).\nk_minus: Rate constant for receptor unbinding (controls decay time).\nV_th: Half-activation voltage for the presynaptic sigmoid.\ndelta: Slope of the presynaptic sigmoid activation.\ngeometry: AbstractGeometry struct for scaling g_max.\n\n\n\n\n\n","title":"MTKNeuralToolkit.CholSynapse"},{"category":"method","location":"#MTKNeuralToolkit.ExpSynapse-Tuple{}","page":"Home","text":"ExpSynapse(; name, g_max=1.0, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nA simple exponential decay synapse. The synaptic gating variable s is driven by a  continuous sigmoidal function of the presynaptic voltage and decays exponentially with time constant τ.\n\nThe current injected into the postsynaptic compartment is: I_syn = g_max * s * (E_rev - V_post)\n\nArguments\n\ng_max: Maximum synaptic conductance.\nτ: Decay time constant of the synapse.\nE_rev: Reversal potential of the synapse.\nV_th: Threshold voltage for presynaptic activation.\nslope: Slope of the presynaptic sigmoid activation.\n\n\n\n\n\n","title":"MTKNeuralToolkit.ExpSynapse"},{"category":"method","location":"#MTKNeuralToolkit.FixedReversal-Tuple{}","page":"Home","text":"fixed_reversal Component: A pure constant voltage source (Nernst battery).\n\n\n\n\n\n","title":"MTKNeuralToolkit.FixedReversal"},{"category":"method","location":"#MTKNeuralToolkit.GlutSynapse-Tuple{}","page":"Home","text":"GlutSynapse(; name, g_max=30.0, E_rev=-70.0, k_minus=0.025, V_th=-35.0, delta=5.0, geometry=NoGeometry())\n\nA continuous glutamatergic synapse model. Behaves identically to CholSynapse but uses  default parameters typical for fast excitatory glutamatergic receptors.\n\nArguments\n\ng_max: Maximum synaptic conductance (scaled by geometry if provided).\nE_rev: Reversal potential of the synapse (e.g., -70 mV or higher for excitatory).\nk_minus: Rate constant for receptor unbinding.\nV_th: Half-activation voltage for the presynaptic sigmoid.\ndelta: Slope of the presynaptic sigmoid activation.\ngeometry: AbstractGeometry struct for scaling g_max.\n\n\n\n\n\n","title":"MTKNeuralToolkit.GlutSynapse"},{"category":"method","location":"#MTKNeuralToolkit.NMDASynapse-Tuple{}","page":"Home","text":"NMDASynapse(; name, g_max=1.0, τ=100.0, E_rev=0.0, V_th=-20.0, Mg_conc=1.0, slope=2.0)\n\nAn N-Methyl-D-Aspartate (NMDA) receptor synapse. It includes the classic voltage-dependent  Magnesium block that reduces conductance at hyperpolarized potentials. The gating variable s  decays with a slow time constant τ.\n\nThe current injected into the postsynaptic compartment is: I_syn = g_max * s * mg_block(V_post) * (E_rev - V_post)\n\nArguments\n\ng_max: Maximum synaptic conductance.\nτ: Slow decay time constant typical of NMDA receptors.\nE_rev: Reversal potential of the synapse (usually near 0 mV).\nV_th: Threshold voltage for presynaptic activation.\nMg_conc: Extracellular Magnesium concentration determining block strength.\nslope: Slope of the presynaptic sigmoid activation.\n\n\n\n\n\n","title":"MTKNeuralToolkit.NMDASynapse"},{"category":"method","location":"#MTKNeuralToolkit.STDPSynapse-Tuple{}","page":"Home","text":"STDPSynapse(; name, g_max=1.0, E_rev=0.0, V_th=0.0, slope=2.0, τ_s=5.0, \n            τ_plus=20.0, τ_minus=20.0, A_plus=0.1, A_minus=0.1, \n            w_init=0.5, w_max=1.0, w_min=0.0)\n\nA continuous, smooth approximation of Spike-Timing-Dependent Plasticity (STDP) with soft bounds. It uses a continuous spike-detector function (sigmoid) and trace variables (x for pre, y for post)  to approximate the relative timing of spikes without requiring discrete event handling.\n\nThe weight w evolves continuously according to: dw/dt = A_plus * (w_max - w) * x * σ(V_post) - A_minus * (w - w_min) * y * σ(V_pre)\n\nwhere x and y are exponentially decaying traces, and σ(V) is a sigmoid acting as a  continuous spike detector. This formulation is purely acausal and ODE-based, making it incredibly  robust for standard differential equation solvers while demonstrating classic STDP behavior.\n\n\n\n\n\n","title":"MTKNeuralToolkit.STDPSynapse"},{"category":"method","location":"#MTKNeuralToolkit.SpikingCapacitor-Tuple{}","page":"Home","text":"SpikingCapacitor Component: Capacitor that automatically resets its voltage when a threshold is crossed \n\n\n\n\n\n","title":"MTKNeuralToolkit.SpikingCapacitor"},{"category":"method","location":"#MTKNeuralToolkit.SynapsePort-Tuple{}","page":"Home","text":"SynapsePort\n\nA boundary connector that exposes the postsynaptic current variable (I_syn)  and binds it to the positive pin (p.i) of a standard electrical port. \n\nThis component is typically used internally by compartment builders to route  synaptic currents into a postsynaptic compartment's CurrentSource.\n\n\n\n\n\n","title":"MTKNeuralToolkit.SynapsePort"},{"category":"method","location":"#MTKNeuralToolkit.VectorizedExpSynapse-Tuple{}","page":"Home","text":"VectorizedExpSynapse(; name, N_pre, N_post, W, g_max=1.0, τ=5.0, E_rev=0.0, V_th=-20.0, slope=2.0)\n\nA vectorized block of exponential synapses representing a dense N_post by N_pre projection.  It accepts an entire weight matrix W mapping presynaptic gating variables to postsynaptic currents.\n\nThe synaptic state s is a vector of length N_pre. The postsynaptic current vector is computed via: I_syn[i] = g_max * sum_j(W[i, j] * s[j]) * (E_rev - V_post[i])\n\nArguments\n\nN_pre: Number of presynaptic elements.\nN_post: Number of postsynaptic elements.\nW: A matrix of connection weights (dimensions N_post x N_pre).\ng_max: Maximum global synaptic conductance.\nτ: Decay time constant.\nE_rev: Reversal potential of the synapse.\nV_th: Threshold voltage for presynaptic activation.\nslope: Slope of the presynaptic sigmoid activation.\n\n\n\n\n\n","title":"MTKNeuralToolkit.VectorizedExpSynapse"},{"category":"method","location":"#MTKNeuralToolkit.build_acausal_network-Tuple{Vector{<:Compartment}}","page":"Home","text":"build_acausal_network(compartments; coupling_specs, synapse_specs, drivers, name)\n\nAssembles a collection of Compartments into a complete Network system.  It handles grounding, wiring driving stimuli, gap junctions (via CouplingSpec),  and chemical synapses (via SynapseSpec).\n\nArguments\n\ncompartments::Vector{<:Compartment}: The compartments making up the network.\ncoupling_specs: A vector of CouplingSpec structs for acausal electrical connections.\nsynapse_specs: A vector of SynapseSpec structs for directed chemical synapses.\ndrivers: A vector of (target, stim) tuples, where target is a compartment or index, and stim is an MTK block, vector, or number.\nname::Symbol: The name of the overall network system.\n\nReturns\n\nA Network struct containing the assembled MTK System.\n\n\n\n\n\n","title":"MTKNeuralToolkit.build_acausal_network"},{"category":"method","location":"#MTKNeuralToolkit.build_compartment-Tuple{Any, Any}","page":"Home","text":"build_compartment(capacitor, channels; name, V_init, topology, ion_config, geometry, morphology)\n\nBuilds a Compartment by connecting a Capacitor, current injectors, and a collection of ion channels. This forms the fundamental electrical unit of a neuron. All positive terminals (p) are connected together  to the membrane potential, and all negative terminals (n) are connected to ground. \n\nArguments\n\ncapacitor: A Capacitor system defining the membrane capacitance.\nchannels: A vector of ion channel systems (e.g., GenericChannel, CaVChannel).\nname::Symbol: The name of the compartment system.\nV_init::Float64: Initial membrane voltage (default -65.0 mV).\ntopology: Scalar() or Vectorized(N) (default Scalar()).\nion_config: NoCalcium() or CalciumTracker() to handle ion pools.\ngeometry: Geometry struct for biophysical scaling (default NoGeometry()).\nmorphology: Morphology struct for spatial data (default NoMorphology()).\n\nReturns\n\nA Compartment struct containing the assembled System and its exposed interfaces.\n\n\n\n\n\n","title":"MTKNeuralToolkit.build_compartment"},{"category":"method","location":"#MTKNeuralToolkit.build_synapse_block-Tuple{Any, Any, Any}","page":"Home","text":"build_synapse_block(pre_comp, post_comp, W; name, synapse_type, kwargs...)\n\nHelper function to create a SynapseSpec using a vectorized synapse block. It automatically determines the pre- and postsynaptic dimensions based on the weight matrix W and binds it to the provided compartments.\n\nArguments\n\npre_comp::Compartment: The presynaptic compartment.\npost_comp::Compartment: The postsynaptic compartment.\nW: The weight matrix (dimensions N_post x N_pre).\nname::Symbol: The name for the synapse block system.\nsynapse_type: The vectorized synapse component to use (defaults to VectorizedExpSynapse).\nkwargs...: Additional keyword arguments passed to synapse_type (e.g., g_max, E_rev).\n\nReturns\n\nA SynapseSpec configured for the network builder.\n\n\n\n\n\n","title":"MTKNeuralToolkit.build_synapse_block"},{"category":"method","location":"#MTKNeuralToolkit.wire_ions!-Tuple{Any, Any, Any, NoCalcium, Any, Any}","page":"Home","text":"wire_ions!(eqs, systems, channels, config, topology, name)\n\nInternal helper function to wire ion dynamics into a compartment's equations and systems list. Uses multiple dispatch to handle different ion configurations.\n\nIf config is NoCalcium, it does nothing.\nIf config is CalciumTracker, it creates a CalciumPool and connects it to all channels in the compartment that expose a ca_port.\n\n\n\n\n\n","title":"MTKNeuralToolkit.wire_ions!"},{"category":"method","location":"#MTKNeuralToolkit.wire_synapses!-Tuple{Vector{Symbolics.Equation}, Vector{ModelingToolkitBase.System}, Vector{SynapseSpec}}","page":"Home","text":"wire_synapses!(eqs, systems, specs)\n\nInternal helper function that wires a collection of SynapseSpecs into the network equations. It binds the presynaptic and postsynaptic voltage variables to the synapse, and pre-collects  convergent synapses by their target current variable to write a single summed equation per target.\n\nReturns a tuple of (driven_syn_targets, block_driven_targets) used for grounding unconnected inputs.\n\n\n\n\n\n","title":"MTKNeuralToolkit.wire_synapses!"},{"category":"section","location":"examples/15_noisy_estimation/#**15.**-Parameter-Estimation-with-Noisy-Data","page":"15 noisy estimation","text":"","title":"15. Parameter Estimation with Noisy Data"},{"category":"section","location":"examples/15_noisy_estimation/#Introduction","page":"15 noisy estimation","text":"In this example, we demonstrate the filtering power of the Prediction Error Method (PEM). We generate data from a true Hodgkin-Huxley neuron, add realistic Gaussian noise to the voltage trace, and then attempt to recover the conductances. The PEM observer channel acts as a feedback controller, absorbing the noise while allowing the optimizer to find the true underlying parameters without overfitting the noise.\n\nusing MTKNeuralToolkit\nusing SymbolicIndexingInterface: getu\nusing MTKNeuralToolkit.HodgkinHuxley: SodiumChannel, PotassiumChannel, LeakChannel\nusing ModelingToolkit: mtkcompile, @named\nusing OrdinaryDiffEq\nusing OrdinaryDiffEqRosenbrock\nusing Optimization\nusing OptimizationOptimJL\nusing SciMLStructures: Tunable, canonicalize, replace\nusing SymbolicIndexingInterface: parameter_values, setp\nusing PreallocationTools\nusing DataInterpolations\nusing SciMLBase\nusing Plots\nusing Markdown\nusing Random","title":"Introduction"},{"category":"section","location":"examples/15_noisy_estimation/#1.-Build-the-True-System-and-Generate-Noisy-Data","page":"15 noisy estimation","text":"top = Scalar()\n\nfunction build_hh_neuron(name::Symbol; gNa=120.0, gK=36.0, gleak=0.3, pem=false, itps=nothing, K=1.0)\n    @named cap  = Capacitor(topology=top, C=1.0)\n    @named na   = SodiumChannel(topology=top, g=gNa)\n    @named k    = PotassiumChannel(topology=top, g=gK)\n    @named leak = LeakChannel(topology=top, g=gleak)\n    channels = [na, k, leak]\n    if pem\n        @named pem_ch = PEMObservationChannel(itps=itps, K_init=K, topology=top)\n        push!(channels, pem_ch)\n    end\n    return build_compartment(cap, channels; name=name, V_init=-65.0, topology=top)\nend\n\ntrue_gNa = 120.0\ntrue_gK  = 36.0\ntrue_gleak = 0.3\n\ntrue_neuron = build_hh_neuron(:true_neuron; gNa=true_gNa, gK=true_gK, gleak=true_gleak)\n\ndrivers = [(1, 8.0)]\ntrue_net = build_acausal_network([true_neuron]; drivers=drivers, name=:true_net)\nEND_TIME= 100.0\n\n\ntrue_sys = mtkcompile(true_net.sys)\ntrue_prob = ODEProblem(true_sys, [], (0.0, END_TIME))\ntimesteps = 0.0:0.1:END_TIME\n\ntrue_sol = solve(true_prob, Rodas5(); saveat=timesteps)\nV_data_clean = true_sol[true_sys.true_neuron.cap.v]\n\nAdd 3 mV Gaussian noise to the data\n\nRandom.seed!(42)\nnoise_level = 3.0\nV_data_noisy = V_data_clean .+ noise_level .* randn(length(V_data_clean))\nitp_V = LinearInterpolation(V_data_noisy, timesteps)","title":"1. Build the True System & Generate Noisy Data"},{"category":"section","location":"examples/15_noisy_estimation/#2.-Setup-the-PEM-Optimization-Problem","page":"15 noisy estimation","text":"We create a model neuron with terrible initial guesses and attach a PEM observer to the noisy data.\n\nguess_gNa = 10.0\nguess_gK  = 100.0\nguess_gleak = 10.3\n\nfit_neuron = build_hh_neuron(:fit_neuron; gNa=guess_gNa, gK=guess_gK, gleak=guess_gleak, pem=true, itps=[itp_V], K=2.0)\nfit_net = build_acausal_network([fit_neuron]; drivers=drivers, name=:fit_net)\nfit_sys = mtkcompile(fit_net.sys)\nfit_prob = ODEProblem(fit_sys, [], (0.0, END_TIME))\n\ngNa_sym = fit_sys.fit_neuron.na.g\ngK_sym  = fit_sys.fit_neuron.k.g\ngleak_sym = fit_sys.fit_neuron.leak.g\n\nsetter = setp(fit_prob, [gNa_sym, gK_sym, gleak_sym])\ndiffcache = DiffCache(copy(canonicalize(Tunable(), parameter_values(fit_prob))[1]))\n\nv_getter = getu(fit_prob, fit_sys.fit_neuron.cap.v)\ni_pem_getter = getu(fit_prob, fit_sys.fit_neuron.pem_ch.i)","title":"2. Setup the PEM Optimization Problem"},{"category":"section","location":"examples/15_noisy_estimation/#3.-Define-Loss-Function-and-Optimize","page":"15 noisy estimation","text":"We calculate the loss based on the PEM observer current. Instead of minimizing the tracking error (which the controller achieves regardless of parameters), we minimize the effort of the controller. This forces the optimizer to find the underlying parameters that naturally generate the data.","title":"3. Define Loss Function & Optimize"},{"category":"section","location":"examples/15_noisy_estimation/#3.-Define-Loss-Function-and-Optimize-2","page":"15 noisy estimation","text":"We calculate a multi-objective loss based on both the tracking error (voltage) and the observer effort (current). This forces the system to track the data while penalizing the controller from \"cheating\" to force bad parameters to fit.\n\nfunction loss(x, p)\n    prob, timesteps, V_data_noisy, setter, diffcache, v_getter, i_pem_getter = p\n\n    ps = parameter_values(prob)\n    buffer = get_tmp(diffcache, x)\n    copyto!(buffer, canonicalize(Tunable(), ps)[1])\n    ps = replace(Tunable(), ps, buffer)\n    setter(ps, x)\n    newprob = remake(prob; p=ps)\n    sol = solve(newprob, Rodas5(); saveat=timesteps, reltol=1e-8, abstol=1e-8)\n\n    if !SciMLBase.successful_retcode(sol.retcode)\n        return Inf\n    end\n\n    V_fit = v_getter(sol)\n    I_pem = i_pem_getter(sol)\n\n    #Multi-objective cost\n    tracking_error = sum(abs2, V_fit .- V_data_noisy) / length(V_data_noisy)\n    observer_effort = sum(abs2, I_pem) / length(I_pem)\n\n    alpha = 1.0\n    beta = 1.0\n\n    return alpha * tracking_error + beta * observer_effort\nend\n\nTuple must also have exactly 7 items:\n\nopt_params = (fit_prob, timesteps, V_data_noisy, setter, diffcache, v_getter, i_pem_getter)\nadtype = AutoForwardDiff()\noptfn = OptimizationFunction(loss, adtype)\noptprob = OptimizationProblem(optfn, [guess_gNa, guess_gK, guess_gleak], opt_params)","title":"3. Define Loss Function & Optimize"},{"category":"section","location":"examples/15_noisy_estimation/#4.-Optimize-and-Plot","page":"15 noisy estimation","text":"To avoid recompiling new systems for the free-running simulations, we simply reuse the compiled fit_sys and set the PEM controller gain (K) to 0.0 to disable the observer.\n\nprintln(\"Starting optimization...\")\n\n(Don't forget to add lb and ub to optprob in Section 3 if you haven't already!)\n\nres = solve(optprob, BFGS(); maxiters=1000)\n\nAssuming the PEM channel has a parameter named K. (If the symbol name is different in your package, just adjust this line)\n\nK_sym = fit_sys.fit_neuron.pem_ch.K\nK_setter = setp(fit_prob, [K_sym])\n\n–- 1. Simulate with recovered parameters (WITH PEM) to get observer current –-\n\nopt_ps = parameter_values(fit_prob)\nopt_buffer = copy(canonicalize(Tunable(), opt_ps)[1])\nopt_ps = replace(Tunable(), opt_ps, opt_buffer)\nsetter(opt_ps, res.u) # set recovered parameters\nopt_prob_pem = remake(fit_prob; p=opt_ps)\nopt_sol_pem = solve(opt_prob_pem, Rodas5(); saveat=timesteps, reltol=1e-6, abstol=1e-6)\n\n–- 2. Pure simulation for INITIAL GUESS (No PEM) –-\n\ninit_ps = parameter_values(fit_prob)\ninit_buffer = copy(canonicalize(Tunable(), init_ps)[1])\ninit_ps = replace(Tunable(), init_ps, init_buffer)\nsetter(init_ps, [guess_gNa, guess_gK, guess_gleak])\nK_setter(init_ps, [0.0]) # disable PEM controller\ninit_prob_free = remake(fit_prob; p=init_ps)\ninit_eval_sol = solve(init_prob_free, Rodas5(); saveat=timesteps)\n\n–- 3. Pure simulation for RECOVERED PARAMETERS (No PEM) –-\n\nopt_gNa, opt_gK, opt_gleak = res.u\nfit_ps = parameter_values(fit_prob)\nfit_buffer = copy(canonicalize(Tunable(), fit_ps)[1])\nfit_ps = replace(Tunable(), fit_ps, fit_buffer)\nsetter(fit_ps, [opt_gNa, opt_gK, opt_gleak])\nK_setter(fit_ps, [0.0]) # disable PEM controller\nfit_prob_free = remake(fit_prob; p=fit_ps)\nfit_eval_sol = solve(fit_prob_free, Rodas5(); saveat=timesteps)\n\n(Plotting code remains exactly the same)\n\np1 = plot(timesteps, V_data_noisy, label=\"Noisy Target\", color=:gray, lw=1, alpha=0.8)\nplot!(p1, timesteps, V_data_clean, label=\"True Clean\", color=:black, lw=2)\nplot!(p1, timesteps, init_eval_sol[fit_sys.fit_neuron.cap.v], label=\"Initial Guess (Free-Running)\", ls=:dot, lw=2, color=:blue)\nplot!(p1, timesteps, fit_eval_sol[fit_sys.fit_neuron.cap.v], label=\"Fit (Free-Running)\", ls=:dash, lw=2, color=:red)\ntitle!(\"Voltage Trace Recovery (Noisy Data)\")\n\nPlot the observer current.\n\nI_obs = i_pem_getter(opt_sol_pem)\np2 = plot(timesteps, I_obs, label=\"Observer Current\", color=:red, lw=1.5)\ntitle!(\"PEM Observer Current (Absorbing Noise)\")\nhline!([0.0], color=:gray, ls=:dot, label=\"0\")\n\np = plot(p1, p2, layout=(2,1), size=(800, 700), legend=:outertop)\nxlabel!(p, \"Time (ms)\")\nylabel!(p, \"V (mV) / I (nA)\")","title":"4. Optimize and Plot"},{"category":"section","location":"examples/15_noisy_estimation/#5.-Parameter-Comparison","page":"15 noisy estimation","text":"Markdown.parse(\"\"\"\n| Parameter | True Value | Initial Guess | Recovered Value |\n|-----------|------------|---------------|-----------------|\n| gNa       | $true_gNa  | $guess_gNa    | $(round(opt_gNa, digits=3)) |\n| gK        | $true_gK   | $guess_gK     | $(round(opt_gK, digits=3)) |\n| gleak     | $true_gleak| $guess_gleak  | $(round(opt_gleak, digits=3)) |\n\"\"\")\n\n\n\nThis page was generated using Literate.jl.","title":"5. Parameter Comparison"}]
}
